757		subtype MAC_ADDRESS_SEGMENT					is string(1 to 2);
758		type		MAC_ADDRESS_SEGMENT_VECTOR	is array (natural range <>) of MAC_ADDRESS_SEGMENT;
759	
760		function mac_split(str : string) return MAC_ADDRESS_SEGMENT_VECTOR is
761			variable input								: string(str'range)											:= str_toUpper(str);
762			variable Segments							: MAC_ADDRESS_SEGMENT_VECTOR(0 to 5)		:= (others => (others => '0'));
763			variable SegmentPointer				: natural																:= 0;
764			variable CharPointer					: natural																:= 2;
765		begin
766	--		report "mac_split of " & str severity NOTE;
767			for i in str'reverse_range loop
768	--			report "  char=" & input(i) severity NOTE;
769				if (to_digit(input(i), 'h') /= -1) then
770					Segments(SegmentPointer)(CharPointer)	:= input(i);
771	--				report "    copy to seg=" & INTEGER'image(SegmentPointer) & "  pos=" & INTEGER'image(CharPointer) severity NOTE;
772					CharPointer					:= CharPointer - 1;
773				elsif ((input(i) = ':') or (input(i) = '-')) then
774					SegmentPointer		:= SegmentPointer + 1;
775					CharPointer				:= 2;
776				else
777					report "ERROR - unknown char [" & input(i) & "]" severity ERROR;
778				end if;
779			end loop;
780	
781			return Segments;
782		end function;
783	
784		-- converts MAC address strings to T_NET_MAC_ADDRESS
785		-- allowed delimiter signs: ':' or '-'
786		function to_net_mac_address(str : string) return T_NET_MAC_ADDRESS is
787			variable Segments				: MAC_ADDRESS_SEGMENT_VECTOR(0 to 5)	:= mac_split(str);
788			variable MAC						: T_NET_MAC_ADDRESS;
789		begin
790			for i in Segments'range loop
791				MAC(i)	:= to_slv(to_natural_hex(Segments(i)), 8);
792			end loop;
793			return MAC;
794		end function;
