824			variable slvv : T_SLVV_8(mac'range);
825		begin
826			for i in mac'range loop
827				slvv(i)	:= mac(i);
828			end loop;
829			return slvv;
830		end function;
831	
832		function to_slvv_8(EthType : T_NET_MAC_ETHERNETTYPE) return T_SLVV_8 is
833			variable slvv : T_SLVV_8(EthType'range);
834		begin
835			for i in EthType'range loop
836				slvv(i)	:= EthType(i);
837			end loop;
838			return slvv;
839		end function;
840	
841		function to_string(mac : T_NET_MAC_ADDRESS) return string is
842			variable str		: string(1 to 18)		:= (others => ':');
843		begin
844			for i in 0 to 5 loop
845				str((i * 3) + 1 to (i * 3) + 2)	:= to_string(mac(5 - i), 'h');
846			end loop;
847			return str(1 to 17);
848		end function;
849	
850		function to_string(EthType : T_NET_MAC_ETHERNETTYPE) return string is
851		begin
852			-- TODO: replace this case-statement by substring(image(EthType), 10,0)
853			case to_slv(EthType) is
854				when to_slv(C_NET_MAC_ETHERNETTYPE_EMPTY) =>				return "Empty";
855				when to_slv(C_NET_MAC_ETHERNETTYPE_ARP) =>					return "ARP";
856				when to_slv(C_NET_MAC_ETHERNETTYPE_IPV4) =>					return "IPv4";
857				when to_slv(C_NET_MAC_ETHERNETTYPE_IPV6) =>					return "IPv6";
858				when to_slv(C_NET_MAC_ETHERNETTYPE_JUMBOFRAMES) =>	return "Jumbo";
859				when to_slv(C_NET_MAC_ETHERNETTYPE_MACCONTROL) =>		return "MACControl";
860				when to_slv(C_NET_MAC_ETHERNETTYPE_QINQ) =>					return "QinQ";
861				when to_slv(C_NET_MAC_ETHERNETTYPE_SNMP) =>					return "SNMP";
862				when to_slv(C_NET_MAC_ETHERNETTYPE_VLAN) =>					return "VLAN";
863				when to_slv(C_NET_MAC_ETHERNETTYPE_WOL) =>					return "WOL";
864	
865				when to_slv(C_NET_MAC_ETHERNETTYPE_SWAP) =>					return "Swap";
866				when to_slv(C_NET_MAC_ETHERNETTYPE_LOOPBACK) =>			return "LoopBack";
867				when others =>																			return "0x" & to_string(to_slv(EthType), 'h');
868			end case;
869		end function;
870	
871		-- ==========================================================================================================================================================
872		-- internet layer: Internet Protocol Version 4 (IPv4)
873		-- ==========================================================================================================================================================
874		function to_net_ipv4_address(slv : T_SLV_32) return T_NET_IPV4_ADDRESS is
875			variable ip					: T_NET_IPV4_ADDRESS;
876		begin
877			for i in 0 to 3 loop
878				ip(i)	:=	slv(((i * 8) + 7) downto (i * 8));
879			end loop;
880			return ip;
881		end function;
882	
883		subtype IPV4_ADDRESS_SEGMENT					is string(1 to 3);
884		type		IPV4_ADDRESS_SEGMENT_VECTOR		is array (natural range <>) of IPV4_ADDRESS_SEGMENT;
885	
886		function ipv4_split(str : string) return IPV4_ADDRESS_SEGMENT_VECTOR is
887			variable input								: string(str'range)											:= str_toUpper(str);
888			variable Segments							: IPV4_ADDRESS_SEGMENT_VECTOR(0 to 3)		:= (others => (others => '0'));
889			variable SegmentPointer				: natural																:= 0;
890			variable CharPointer					: natural																:= 3;
891		begin
892	--		report "ipv4_split of " & str severity NOTE;
893			for i in str'reverse_range loop
894	--			report "  char=" & input(i) severity NOTE;
895				if (to_digit(input(i), 'd') /= -1) then
896					Segments(SegmentPointer)(CharPointer)	:= input(i);
897	--				report "    copy to seg=" & INTEGER'image(SegmentPointer) & "  pos=" & INTEGER'image(CharPointer) severity NOTE;
898					CharPointer					:= CharPointer - 1;
899				elsif (input(i) = '.') then
900					SegmentPointer		:= SegmentPointer + 1;
901					CharPointer				:= 3;
902				else
903					report "ERROR - unknown char" severity ERROR;
904				end if;
905			end loop;
906	
907			return Segments;
908		end function;
909	
910		-- converts MAC address strings to T_NET_MAC_ADDRESS
911		--	allowed delimiter sign: '.'
912		function to_net_ipv4_address(str : string) return T_NET_IPV4_ADDRESS is
913			variable Segments				: IPV4_ADDRESS_SEGMENT_VECTOR(0 to 3)	:= ipv4_split(str);
914			variable Segment				: T_SLV_8;
915			variable IP							: T_NET_IPV4_ADDRESS;
916		begin
917			for i in Segments'range loop
918				IP(i) := to_slv(to_natural_dec(Segments(i)), 8);
919			end loop;
920			return IP;
921		end function;
922	
923		function to_net_ipv4_TYPE_of_service(slv : T_SLV_8)	return T_NET_IPV4_TYPE_OF_SERVICE is
924			variable tos			: T_NET_IPV4_TYPE_OF_SERVICE;
925		begin
926			tos.Precedence		:= slv(2 downto 0);
927			tos.Delay					:= slv(3);
928			tos.Throughput		:= slv(4);
929			tos.Relibility		:= slv(5);
930			return tos;
931		end function;
932	
933		function to_slv(ip : T_NET_IPV4_ADDRESS) return std_logic_vector is
934			variable slv						: T_SLV_32;
935		begin
936			for i in 0 to 3 loop
937				slv(((i * 8) + 7) downto (i * 8))		:= ip(i);
938			end loop;
939			return slv;
940		end function;
941	--
942	--	function to_slv(proto : T_NET_IPV4_PROTOCOL) return STD_LOGIC_VECTOR is
943	--		variable slv						: T_SLV_8;
944	--	begin
945	--		slv := proto;
946	--		return slv;
947	--	end function;
948	
949		function to_slv(tos : T_NET_IPV4_TYPE_OF_SERVICE)	return std_logic_vector is
950			variable slv						: T_SLV_8;
951		begin
952			slv(2 downto 0)		:= tos.Precedence;
953			slv(3)						:= tos.Delay;
954			slv(4)						:= tos.Throughput;
955			slv(5)						:= tos.Relibility;
956			slv(7 downto 6)		:= "00";
957			return slv;
958		end function;
959	
960		function to_slvv_8(ip : T_NET_IPV4_ADDRESS) return T_SLVV_8 is
961			variable slvv						: T_SLVV_8(ip'range);
962		begin
963			for i in ip'range loop
964				slvv(i)	:= ip(i);
965			end loop;
966			return slvv;
967		end function;
968	
969		function to_string(IP : T_NET_IPV4_ADDRESS) return string is
970			variable temp						: string(1 to 16)			:= (others => '.');
971			variable str						: string(1 to 3);
972			variable len						: positive;
973			variable CharPointer		: natural							:= 1;
974	
975		begin
976	--		report "converting IPv4 address" severity NOTE;
977			for i in 3 downto 0 loop
978	--			report "  I=" & INTEGER'image(i) & "  IP(i)=" & INTEGER'image(to_integer(unsigned(IP(i)))) & "  CP=" & INTEGER'image(CharPointer) severity NOTE;
979	
980				str := resize(integer'image(to_integer(unsigned(IP(i)))), str'length);
981				len	:= str_length(str);
982				temp(CharPointer to CharPointer + len - 1)	:= str(1 to len);
983				CharPointer := CharPointer + len + 1;
984			end loop;
985	
986			return temp(1 to CharPointer - 2);
987		end function;
988	
989		-- ==========================================================================================================================================================
990		-- internet layer: Internet Protocol Version 6 (IPv6)
991		-- ==========================================================================================================================================================
992		function to_net_ipv6_address(slv : T_SLV_128) return T_NET_IPV6_ADDRESS is
993			variable ip					: T_NET_IPV6_ADDRESS;
994		begin
995			for i in 0 to 15 loop
996				ip(i)	:=	slv(((i * 8) + 7) downto (i * 8));
997			end loop;
998	
999			return ip;
1000		end function;
1001	
1002		subtype IPV6_ADDRESS_SEGMENT					is string(1 to 4);
1003		type		IPV6_ADDRESS_SEGMENT_VECTOR		is array (natural range <>) of IPV6_ADDRESS_SEGMENT;
1004	
1005		function ipv6_split(str : string) return IPV6_ADDRESS_SEGMENT_VECTOR is
1006			variable input								: string(str'range)											:= str_toUpper(str);
1007			variable Segments							: IPV6_ADDRESS_SEGMENT_VECTOR(0 to 7)		:= (others => (others => '0'));
1008			variable DelimiterPointer			: natural																:= 0;
1009			variable SegmentPointer				: natural																:= 0;
1010			variable CharPointer					: natural																:= 4;
1011			variable RemainingDelimiters	: natural																:= 0;
1012		begin
1013	--		report "ipv6_split of " & str severity NOTE;
1014	
1015			for i in str'reverse_range loop
1016	--			report "  char=" & input(i) severity NOTE;
1017				if (to_digit(input(i), 'h') /= -1) then
1018					Segments(SegmentPointer)(CharPointer)	:= input(i);
1019	--				report "    copy to seg=" & INTEGER'image(SegmentPointer) & "  pos=" & INTEGER'image(CharPointer) severity NOTE;
1020					CharPointer					:= CharPointer - 1;
1021					DelimiterPointer		:= 0;
1022				elsif (input(i) = ':') then
1023					if (DelimiterPointer = 0) then
1024						SegmentPointer		:= SegmentPointer + 1;
1025						CharPointer				:= 4;
1026						DelimiterPointer	:= i;
1027					else
1028						-- count remaining segments-delimiters
1029						for j in i - 1 downto input'low loop
1030							if (input(j) = ':') then
1031								RemainingDelimiters	:= RemainingDelimiters + 1;
1032							end if;
1033						end loop;
1034	--					report "    lookahead rem-del=" & INTEGER'image(RemainingDelimiters) severity NOTE;
1035						SegmentPointer		:= 7 - RemainingDelimiters;
1036						CharPointer				:= 4;
1037						DelimiterPointer	:= 0;
1038					end if;
1039				else
1040					report "    ERROR - unknown char" severity ERROR;
1041				end if;
1042			end loop;
1043	
1044			return Segments;
1045		end function;
1046	
1047		function to_net_ipv6_address(str : string) return T_NET_IPV6_ADDRESS is
1048			variable Segments				: IPV6_ADDRESS_SEGMENT_VECTOR(0 to 7)	:= ipv6_split(str);
1049			variable Segment				: T_SLV_16;
1050			variable IP							: T_NET_IPV6_ADDRESS;
1051		begin
1052			for i in Segments'range loop
1053				Segment								:= to_slv(to_natural_hex(Segments(i)), 16);
1054				IP(i * 2)							:= Segment(7 downto 0);
1055				IP((i * 2) + 1)				:= Segment(15 downto 8);
1056			end loop;
1057			return IP;
1058		end function;
1059	
1060		function to_net_ipv6_prefix(str : string) return T_NET_IPV6_PREFIX is
1061			variable Pos						: positive;
1062			variable Prefix					: T_NET_IPV6_PREFIX;
1063			variable IPv6Address		: T_NET_IPV6_ADDRESS;
1064			variable Len						: natural;
1065		begin
1066			for i in str'reverse_range loop
1067				if (str(i) = '/') then
1068					Pos := i;
1069					exit;
1070				end if;
1071			end loop;
1072	
1073			if (Pos = str'high) then report "syntax error in IPv6 prefix: " & str severity ERROR;		end if;
1074	
1075			IPv6Address							:= to_net_ipv6_address(str(str'low to Pos - 1));
1076			Len											:= integer'value(str(Pos + 1 to str'high));
1077	
1078			if (not ((0 < Len) and (Len < 128))) then																								report "IPv6 prefix length is out of range: IPv6=" & str & " Length=" & integer'image(Len) severity ERROR;	end if;
1079			if ((to_slv(IPv6Address) and genmask_low(128 - Len, 128)) /= (127 downto 0 => '0')) then report "IPv6 prefix is longer then it's mask: IPv6=" & str severity ERROR;																	end if;
1080	
1081			Prefix.Prefix						:= IPv6Address;
1082			Prefix.PrefixLength			:= to_slv(Len, Prefix.PrefixLength'length);
1083			return Prefix;
1084		end function;
1085	
1086		function to_slv(ip : T_NET_IPV6_ADDRESS) return std_logic_vector is
1087			variable slv						: T_SLV_128;
1088		begin
1089			for i in 0 to 15 loop
1090				slv(((i * 8) + 7) downto (i * 8))		:= ip(i);
1091			end loop;
1092			return slv;
1093		end function;
1094	
1095		function to_slvv_8(ip : T_NET_IPV6_ADDRESS) return T_SLVV_8 is
1096			variable slvv						: T_SLVV_8(ip'range);
1097		begin
1098			for i in ip'range loop
1099				slvv(i)	:= ip(i);
1100			end loop;
1101			return slvv;
1102		end function;
1103	
1104		function to_string(IP : T_NET_IPV6_ADDRESS) return string is
1105			variable temp						: string(1 to 40)			:= (others => ':');
1106			variable CharPointer		: natural							:= 1;
1107			variable Char						: character;
1108	
1109			variable copy						: boolean							:= FALSE;
1110		begin
1111			for i in 7 downto 0 loop
1112				temp(CharPointer + 0 to CharPointer + 1)	:= to_string(IP((i * 2) + 1), 'h');
1113				temp(CharPointer + 2 to CharPointer + 3)	:= to_string(IP( i * 2), 'h');
1114				CharPointer																:= CharPointer + 5;
1115			end loop;
1116	
1117			-- compress string - remove leading zeros
1118	--		report "compressing IPv6 address" severity NOTE;
1119			CharPointer			:= 1;
1120			for i in temp'range loop
1121	--			report "  I=" & INTEGER'image(i) & "  char=" & temp(i) & "  CP=" & INTEGER'image(CharPointer) & "  copy=" & to_string(copy) severity NOTE;
1122	
1123				if (copy = FALSE) then
1124					if ((temp(i) = '0') and (temp(i + 1) /= ':')) then
1125						null;
1126					else
1127						temp(CharPointer)	:= temp(i);
1128						CharPointer				:= CharPointer + 1;
1129						copy							:= TRUE;
1130					end if;
1131				else
1132					if (temp(i) = ':') then
1133						copy							:= FALSE;
1134					end if;
1135					temp(CharPointer)		:= temp(i);
1136					CharPointer					:= CharPointer + 1;
1137				end if;
1138			end loop;
1139	
1140			return temp(1 to CharPointer - 2);
1141		end function;
1142	
1143		function to_string(Prefix : T_NET_IPV6_PREFIX)	return string is
1144		begin
1145			return to_string(Prefix.Prefix) & "/" & to_string(Prefix.PrefixLength, 'd');
1146		end function;
1147	end package body;
1148

