31	library IEEE;
32	use			IEEE.STD_LOGIC_1164.all;
33	use			IEEE.NUMERIC_STD.all;
34	
35	library PoC;
36	use			PoC.config.all;
37	use			PoC.utils.all;
38	use			PoC.vectors.all;
39	
40	
41	entity net_FrameChecksum is
42		generic (
43			MAX_FRAMES										: positive				:= 8;
44			MAX_FRAME_LENGTH							: positive				:= 2048;
45			META_BITS											: T_POSVEC				:= (0 => 8);
46			META_FIFO_DEPTH								: T_POSVEC				:= (0 => 16)
47		);
48		port (
49			Clock													: in	std_logic;
50			Reset													: in	std_logic;
51			-- IN port
52			In_Valid											: in	std_logic;
53			In_Data												: in	T_SLV_8;
54			In_SOF												: in	std_logic;
55			In_EOF												: in	std_logic;
56			In_Ack												: out	std_logic;
57			In_Meta_rst										: out	std_logic;
58			In_Meta_nxt										: out	std_logic_vector(META_BITS'length - 1 downto 0);
59			In_Meta_Data									: in	std_logic_vector(isum(META_BITS) - 1 downto 0);
60			-- OUT port
61			Out_Valid											: out	std_logic;
62			Out_Data											: out	T_SLV_8;
63			Out_SOF												: out	std_logic;
64			Out_EOF												: out	std_logic;
65			Out_Ack												: in	std_logic;
66			Out_Meta_rst									: in	std_logic;
67			Out_Meta_nxt									: in	std_logic_vector(META_BITS'length - 1 downto 0);
68			Out_Meta_Data									: out	std_logic_vector(isum(META_BITS) - 1 downto 0);
69			Out_Meta_Length								: out	T_SLV_16;
70			Out_Meta_Checksum							: out	T_SLV_16
71		);
72	end entity;
73	
74	-- FIXME: review writer-FSM: check full signals => block incoming words/frames if datafifo or metafifo is full
75	
76	architecture rtl of net_FrameChecksum is
77		attribute FSM_ENCODING						: string;
78	
79		type T_WRITER_STATE is			(ST_IDLE, ST_FRAME, ST_CARRY_1, ST_CARRY_2);
80		type T_METAWRITER_STATE is	(ST_IDLE, ST_METADATA);
81		type T_READER_STATE is			(ST_IDLE, ST_FRAME);
82	
83		signal Writer_State						: T_WRITER_STATE																			:= ST_IDLE;
84		signal Writer_NextState				: T_WRITER_STATE;
85		signal MetaWriter_State				: T_METAWRITER_STATE																	:= ST_IDLE;
86		signal MetaWriter_NextState		: T_METAWRITER_STATE;
87		signal Reader_State						: T_READER_STATE																			:= ST_IDLE;
88		signal Reader_NextState				: T_READER_STATE;
89	
90		signal Checksum_rst						: std_logic;
91		signal Checksum_en						: std_logic;
92		signal Checksum_Data_us				: unsigned(In_Data'range);
93		signal Checksum0_nxt_us				: unsigned(In_Data'length downto 0);
94		signal Checksum0_d_us					: unsigned(In_Data'length downto 0)										:= (others => '0');
95		signal Checksum0_nxt_cy				: std_logic;
96		signal Checksum1_nxt_us				: unsigned(In_Data'range);
97		signal Checksum1_d_us					: unsigned(In_Data'range)															:= (others => '0');
98		signal Checksum								: T_SLV_16;
99	
100		constant WORDCOUNTER_BITS			: positive																						:= log2ceilnz(MAX_FRAME_LENGTH);
101		signal WordCounter_rst				: std_logic;
102		signal WordCounter_en					: std_logic;
103		signal WordCounter_us					: unsigned(WORDCOUNTER_BITS - 1 downto 0)							:= to_unsigned(1, log2ceilnz(MAX_FRAME_LENGTH));
104		signal WordCount							: std_logic_vector(WORDCOUNTER_BITS + 15 downto 16);
105	
106		signal FrameCommit						: std_logic;
107	
108		constant DATA_BITS						: positive																						:= 8;
109		constant EOF_BIT							: natural																							:= DATA_BITS;
110	
111		signal DataFIFO_put						: std_logic;
112		signal DataFIFO_DataIn				: std_logic_vector(DATA_BITS downto 0);
113		signal DataFIFO_Full					: std_logic;
114		signal DataFIFO_got						: std_logic;
115		signal DataFIFO_DataOut				: std_logic_vector(DATA_BITS downto 0);
116		signal DataFIFO_Valid					: std_logic;
117	
118		constant META_MISC_BITS				: positive																						:= Checksum'length + WordCount'length;
119	
120		signal MetaFIFO_Misc_put			: std_logic;
121		signal MetaFIFO_Misc_DataIn		: std_logic_vector(META_MISC_BITS - 1 downto 0);
122		signal MetaFIFO_Misc_Full			: std_logic;
123		signal MetaFIFO_Misc_got			: std_logic;
124		signal MetaFIFO_Misc_DataOut	: std_logic_vector(META_MISC_BITS - 1 downto 0);
125		signal MetaFIFO_Misc_Valid		: std_logic;
126	
127		signal Meta_rst								: std_logic_vector(META_BITS'length - 1 downto 0);
128	
129	begin
130	
131		process(Clock)
132		begin
133			if rising_edge(Clock) then
134				if (Reset = '1') then
135					Writer_State					<= ST_IDLE;
136					Reader_State					<= ST_IDLE;
137				else
138					Writer_State					<= Writer_NextState;
139					Reader_State					<= Reader_NextState;
140				end if;
141			end if;
142		end process;
143	
144		process(Writer_State,
145						In_Valid, In_SOF, In_EOF, In_Data,
146						WordCounter_us, Checksum0_nxt_cy,
147						DataFIFO_Full, MetaFIFO_Misc_Full)
148		begin
149			Writer_NextState								<= Writer_State;
150	
151			DataFIFO_put										<= '0';
152			MetaFIFO_Misc_put								<= '0';
153	
154			In_Ack													<= not DataFIFO_Full;
155	
156			WordCounter_rst									<= '0';
157			WordCounter_en									<= '0';
158	
159			Checksum_rst										<= '0';
160			Checksum_en											<= '0';
161			Checksum_Data_us								<= unsigned(In_Data);
162	
163			case Writer_State is
164				when ST_IDLE =>
165					if ((In_Valid and In_SOF and (not DataFIFO_Full)) = '1') then
166						WordCounter_en						<= '1';
167						Checksum_en								<= '1';
168						DataFIFO_put							<= In_Valid;
169	
170						if (In_EOF = '1') then
171							MetaFIFO_Misc_put						<= '1';
172	
173							Writer_NextState				<= ST_IDLE;
174						else
175							Writer_NextState				<= ST_FRAME;
176						end if;
177					end if;
178	
179				when ST_FRAME =>
180					DataFIFO_put								<= In_Valid;
181	
182					if ((In_Valid and (not DataFIFO_Full)) = '1') then
183						WordCounter_en						<= '1';
184						Checksum_en								<= '1';
185	
186						if (In_EOF = '1') then
187							WordCounter_en					<= '0';
188	
189							if (Checksum0_nxt_cy = '0') then
190								WordCounter_rst			<= '1';
191								Checksum_rst				<= '1';
192	
193								MetaFIFO_Misc_put				<= '1';
194	
195								Writer_NextState		<= ST_IDLE;
196							else
197								Writer_NextState		<= ST_CARRY_1;
198							end if;
199						end if;
200					end if;
201	
202				when ST_CARRY_1 =>
203					In_Ack											<= '0';
204	
205					Checksum_Data_us						<= (others => '0');
206	
207					if (Checksum0_nxt_cy = '0') then
208						Checksum_rst							<= '1';
209						WordCounter_rst						<= '1';
210	
211						MetaFIFO_Misc_put							<= '1';
212	
213						Writer_NextState					<= ST_IDLE;
214					else
215						Checksum_en								<= '1';
216	
217						Writer_NextState					<= ST_CARRY_2;
218					end if;
219	
220				when ST_CARRY_2 =>
221					In_Ack											<= '0';
222	
223					Checksum_Data_us						<= (others => '0');
224					Checksum_rst								<= '1';
225					WordCounter_rst							<= '1';
226	
227					MetaFIFO_Misc_put								<= '1';
228	
229					Writer_NextState						<= ST_IDLE;
230	
231			end case;
232		end process;
233	
234	
235		process(Reader_State,
236						Out_Ack,
237						DataFIFO_Valid, DataFIFO_DataOut,
238						MetaFIFO_Misc_Valid, MetaFIFO_Misc_DataOut)
239		begin
240			Reader_NextState								<= Reader_State;
241	
242			Out_Valid												<= '0';
243			Out_Data												<= DataFIFO_DataOut(Out_Data'range);
244			Out_SOF													<= '0';
245			Out_EOF													<= DataFIFO_DataOut(EOF_BIT);
246			Out_Meta_Checksum								<= MetaFIFO_Misc_DataOut(Checksum'range);
247			Out_Meta_Length									<= resize(MetaFIFO_Misc_DataOut(WordCount'range), Out_Meta_Length'length);
248	
249			DataFIFO_got										<= '0';
250	
251			case Reader_State is
252				when ST_IDLE =>
253					Out_SOF											<= '1';
254	
255					if ((DataFIFO_Valid and MetaFIFO_Misc_Valid) = '1') then
256						Out_Valid									<= '1';
257	
258						if (Out_Ack	 = '1') then
259							DataFIFO_got						<= '1';
260	
261							if (DataFIFO_DataOut(EOF_BIT) = '0') then
262								Reader_NextState			<= ST_FRAME;
263							end if;
264						end if;
265					end if;
266	
267				when ST_FRAME =>
268					Out_Valid										<= DataFIFO_Valid;
269	
270					if (Out_Ack	 = '1') then
271						DataFIFO_got							<= '1';
272	
273						if (DataFIFO_DataOut(EOF_BIT) = '1') then
274							Reader_NextState				<= ST_IDLE;
275						end if;
276					end if;
277	
278			end case;
279		end process;
280	
281		process(Clock)
282		begin
283			if rising_edge(Clock) then
284				if (WordCounter_rst = '1') then
285					WordCounter_us		<= to_unsigned(1, WordCounter_us'length);
286				elsif (WordCounter_en = '1') then
287					WordCounter_us		<= WordCounter_us + 1;
288				end if;
289			end if;
290		end process;
291	
292		Checksum0_nxt_cy		<= Checksum0_nxt_us(Checksum0_nxt_us'high);
293		Checksum0_nxt_us		<= ('0' & Checksum1_d_us) + ('0' & Checksum_Data_us) + ((Checksum1_d_us'range => '0') & Checksum0_d_us(Checksum0_d_us'high));
294		Checksum1_nxt_us		<= Checksum0_d_us(Checksum1_d_us'range);
295	
296		process(Clock)
297		begin
298			if rising_edge(Clock) then
299				if (Checksum_rst = '1') then
300					Checksum0_d_us			<= (others => '0');
301					Checksum1_d_us			<= (others => '0');
302				elsif (Checksum_en = '1') then
303					Checksum0_d_us			<= Checksum0_nxt_us;
304					Checksum1_d_us			<= Checksum1_nxt_us;
305				end if;
306			end if;
307		end process;
308	
309		Checksum			<= std_logic_vector(Checksum0_nxt_us(Checksum1_nxt_us'range)) & std_logic_vector(Checksum1_nxt_us);
310		WordCount			<= std_logic_vector(WordCounter_us);
311	
312		DataFIFO_DataIn(In_Data'range)		<= In_Data;
313		DataFIFO_DataIn(EOF_BIT)					<= In_EOF;
314	
315		DataFIFO : entity PoC.fifo_cc_got
316			generic map (
317				D_BITS							=> DataFIFO_DataIn'length,			-- Data Width
318				MIN_DEPTH						=> MAX_FRAME_LENGTH,						-- Minimum FIFO Depth
319				DATA_REG						=> FALSE,												-- Store Data Content in Registers
320				STATE_REG						=> TRUE,												-- Registered Full/Empty Indicators
321				OUTPUT_REG					=> TRUE,												-- Registered FIFO Output
322				ESTATE_WR_BITS			=> 0,														-- Empty State Bits
323				FSTATE_RD_BITS			=> 0														-- Full State Bits
324			)
325			port map (
326				clk									=> Clock,
327				rst									=> Reset,
328				-- Write Interface
329				put									=> DataFIFO_put,
330				din									=> DataFIFO_DataIn,
331				full								=> DataFIFO_Full,
332				estate_wr						=> open,
333				-- Read Interface
334				got									=> DataFIFO_got,
335				valid								=> DataFIFO_Valid,
336				dout								=> DataFIFO_DataOut,
337				fstate_rd						=> open
338			);
339	
340		MetaFIFO_Misc_DataIn(Checksum'range)		<= ite((WordCounter_us(0) = to_sl(Writer_State /= ST_CARRY_1)), Checksum, swap(Checksum, 8));
341		MetaFIFO_Misc_DataIn(WordCount'range)		<= WordCount;
342	
343		MetaFIFO_Misc : entity PoC.fifo_cc_got
344			generic map (
345				D_BITS							=> MetaFIFO_Misc_DataIn'length,							-- Data Width
346				MIN_DEPTH						=> MAX_FRAMES,															-- Minimum FIFO Depth
347				DATA_REG						=> TRUE,																		-- Store Data Content in Registers
348				STATE_REG						=> TRUE,																		-- Registered Full/Empty Indicators
349				OUTPUT_REG					=> FALSE,																		-- Registered FIFO Output
350				ESTATE_WR_BITS			=> 0,																				-- Empty State Bits
351				FSTATE_RD_BITS			=> 0																				-- Full State Bits
352			)
353			port map (
354				clk									=> Clock,
355				rst									=> Reset,
356				-- Write Interface
357				put									=> MetaFIFO_Misc_put,
358				din									=> MetaFIFO_Misc_DataIn,
359				full								=> MetaFIFO_Misc_Full,
360				estate_wr						=> open,
361				-- Read Interface
362				got									=> MetaFIFO_Misc_got,
363				valid								=> MetaFIFO_Misc_Valid,
364				dout								=> MetaFIFO_Misc_DataOut,
365				fstate_rd						=> open
366			);
367	
368		Out_Meta_Length					<= resize(MetaFIFO_Misc_DataOut(WordCount'range), Out_Meta_Length'length);
369		Out_Meta_Checksum				<= MetaFIFO_Misc_DataOut(Checksum'range);
370	
371		FrameCommit							<= DataFIFO_Valid and DataFIFO_DataOut(EOF_BIT) and Out_Ack;
372		MetaFIFO_Misc_got				<= FrameCommit;
373	
374		genMeta : for i in 0 to META_BITS'length - 1 generate
375			signal MetaFIFO_put						: std_logic;
376			signal MetaFIFO_DataIn				: std_logic_vector(META_BITS(i) - 1 downto 0);
377			signal MetaFIFO_Full					: std_logic;
378			signal MetaFIFO_got						: std_logic;
379			signal MetaFIFO_DataOut				: std_logic_vector(META_BITS(i) - 1 downto 0);
380			signal MetaFIFO_Valid					: std_logic;
381			signal MetaFIFO_Commit				: std_logic;
382			signal MetaFIFO_Rollback			: std_logic;
383	
384			signal Writer_CounterControl	: std_logic																																:= '0';
385	
386			signal Writer_Counter_rst			: std_logic;
387			signal Writer_Counter_en			: std_logic;
388			signal Writer_Counter_us			: unsigned(log2ceilnz(META_FIFO_DEPTH(i) * MAX_FRAMES) - 1 downto 0)			:= (others => '0');
389		begin
390			Writer_Counter_rst		<= '0';		-- FIXME: is this correct?
391	
392			process(Clock)
393			begin
394				if rising_edge(Clock) then
395					if (Reset = '1') then
396						Writer_CounterControl			<= '0';
397					elsif ((In_Valid and In_SOF) = '1') then
398						Writer_CounterControl		<= '1';
399					elsif (Writer_Counter_us = (META_FIFO_DEPTH(i) - 1)) then
400						Writer_CounterControl		<= '0';
401					end if;
402				end if;
403			end process;
404	
405			Writer_Counter_en		<= (In_Valid and In_SOF) or Writer_CounterControl;
406	
407			process(Clock)
408			begin
409				if rising_edge(Clock) then
410					if ((Reset or Writer_Counter_rst) = '1') then
411						Writer_Counter_us					<= (others => '0');
412					elsif (Writer_Counter_en = '1') then
413						Writer_Counter_us				<= Writer_Counter_us + 1;
414					end if;
415				end if;
416			end process;
417	
418			Meta_rst(i)					<= not Writer_Counter_en;
419			In_Meta_nxt(i)			<= Writer_Counter_en;
420	
421			MetaFIFO_put				<= Writer_Counter_en;
422			MetaFIFO_DataIn			<= In_Meta_Data(high(META_BITS, i) downto low(META_BITS, i));
423	
424			MetaFIFO : entity PoC.fifo_cc_got_tempgot
425				generic map (
426					D_BITS							=> MetaFIFO_DataIn'length,							-- Data Width
427					MIN_DEPTH						=> (META_FIFO_DEPTH(i) * MAX_FRAMES),		-- Minimum FIFO Depth
428					DATA_REG						=> TRUE,																-- Store Data Content in Registers
429					STATE_REG						=> TRUE,																-- Registered Full/Empty Indicators
430					OUTPUT_REG					=> FALSE,																-- Registered FIFO Output
431					ESTATE_WR_BITS			=> 0,																		-- Empty State Bits
432					FSTATE_RD_BITS			=> 0																		-- Full State Bits
433				)
434				port map (
435					clk									=> Clock,
436					rst									=> Reset,
437					-- Write Interface
438					put									=> MetaFIFO_put,
439					din									=> MetaFIFO_DataIn,
440					full								=> MetaFIFO_Full,
441					estate_wr						=> open,
442					-- Read Interface
443					got									=> MetaFIFO_got,
444					valid								=> MetaFIFO_Valid,
445					dout								=> MetaFIFO_DataOut,
446					fstate_rd						=> open,
447	
448					commit							=> MetaFIFO_Commit,
449					rollback						=> MetaFIFO_Rollback
450				);
451	
452			MetaFIFO_got				<= Out_Meta_nxt(i);
453			MetaFIFO_Commit			<= FrameCommit;
454			MetaFIFO_Rollback		<= Out_Meta_rst;
455	
456			Out_Meta_Data(high(META_BITS, i) downto low(META_BITS, i))	<= MetaFIFO_DataOut;
457		end generate;
458	
459		In_Meta_rst						<= slv_and(Meta_rst);
460	
461	end architecture;
462

