88		function getInterfaceAddresses(MAC_CONFIG : T_NET_MAC_CONFIGURATION_VECTOR) return T_NET_MAC_ADDRESS_VECTOR is
89			variable temp : T_NET_MAC_ADDRESS_VECTOR(MAC_CONFIG'range);
90		begin
91			for i in MAC_CONFIG'range loop
92				temp(i) := MAC_CONFIG(i).Interface.Address;
93			end loop;
94	
95			return temp;
96		end function;
97	
98		function getInterfaceMasks(MAC_CONFIG : T_NET_MAC_CONFIGURATION_VECTOR) return T_NET_MAC_ADDRESS_VECTOR is
99			variable temp : T_NET_MAC_ADDRESS_VECTOR(MAC_CONFIG'range);
100		begin
101			for i in MAC_CONFIG'range loop
102				temp(i) := MAC_CONFIG(i).Interface.Mask;
103			end loop;
104	
105			return temp;
106		end function;
