108		function getSourceFilterCount(Interfaces : T_NET_MAC_INTERFACE_VECTOR) return natural is
109			variable count : natural		:= 0;
110		begin
111			for i in Interfaces'range loop
112				if ((Interfaces(i).Address /= C_NET_MAC_ADDRESS_EMPTY) or (Interfaces(i).Mask /= C_NET_MAC_MASK_EMPTY)) then
113					count := count + 1;
114				end if;
115			end loop;
116	
117			return count;
118		end function;
