120		function getSourceFilterAddresses(Interfaces : T_NET_MAC_INTERFACE_VECTOR) return T_NET_MAC_ADDRESS_VECTOR is
121			variable temp : T_NET_MAC_ADDRESS_VECTOR(Interfaces'range);
122		begin
123			for i in Interfaces'range loop
124				temp(i) := Interfaces(i).Address;
125			end loop;
126	
127			return temp;
128		end function;
