130		function getSourceFilterMasks(Interfaces : T_NET_MAC_INTERFACE_VECTOR) return T_NET_MAC_ADDRESS_VECTOR is
131			variable temp : T_NET_MAC_ADDRESS_VECTOR(Interfaces'range);
132		begin
