140		function getTypeSwitchCount(Types : T_NET_MAC_ETHERNETTYPE_VECTOR) return natural is
141			variable count : natural		:= 0;
142		begin
143			for i in Types'range loop
144				if (Types(i) /= C_NET_MAC_ETHERNETTYPE_EMPTY) then
145					count := count + 1;
