152		function calcPortIndex(MAC_CONFIG : T_NET_MAC_CONFIGURATION_VECTOR; CurrentInterfaceID : natural) return natural is
153			variable count : natural		:= 0;
154		begin
155			if (CurrentInterfaceID = 0) then
156				return 0;
157			end if;
158	
159			for i in 0 to CurrentInterfaceID - 1 loop
160				count := count + getTypeSwitchCount(MAC_CONFIG(i).TypeSwitch);
161			end loop;
