167		constant PORTS															: positive												:= getPortCount(MAC_CONFIG);
168		constant INTERFACE_COUNT										: positive												:= MAC_CONFIG'length;
169		constant INTERFACE_ADDRESSES								: T_NET_MAC_ADDRESS_VECTOR				:= getInterfaceAddresses(MAC_CONFIG);
170		constant INTERFACE_MASKS										: T_NET_MAC_ADDRESS_VECTOR				:= getInterfaceMasks(MAC_CONFIG);
171	
172		signal DestEth_RX_Valid											: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
173		signal DestEth_RX_Data											: T_SLVV_8(INTERFACE_COUNT - 1 downto 0);
174		signal DestEth_RX_SOF												: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
175		signal DestEth_RX_EOF												: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
176		signal DestEth_RX_Meta_DestMACAddress_Data	: T_SLVV_8(INTERFACE_COUNT - 1 downto 0);
177	
178		signal SrcEth_RX_Ack												: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
179		signal SrcEth_RX_Meta_rst										: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
180		signal SrcEth_RX_Meta_DestMACAddress_nxt		: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
181	
182		signal EthType_TX_Valid											: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
183		signal EthType_TX_Data											: T_SLVV_8(INTERFACE_COUNT - 1 downto 0);
184		signal EthType_TX_SOF												: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
185		signal EthType_TX_EOF												: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
186		signal EthType_TX_Meta_DestMACAddress_Data	: T_SLVV_8(INTERFACE_COUNT - 1 downto 0);
187	
188		signal SrcEth_TX_Valid											: std_logic;
189		signal SrcEth_TX_Data												: T_SLV_8;
190		signal SrcEth_TX_SOF												: std_logic;
191		signal SrcEth_TX_EOF												: std_logic;
192		signal SrcEth_TX_Ack												: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
193		signal SrcEth_TX_Meta_rst										: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
194		signal SrcEth_TX_Meta_DestMACAddress_nxt		: std_logic_vector(INTERFACE_COUNT - 1 downto 0);
195		signal SrcEth_TX_Meta_DestMACAddress_Data		: T_SLV_8;
196	
197		signal DestEth_TX_Ack												: std_logic;
198		signal DestEth_TX_Meta_rst									: std_logic;
199		signal DestEth_TX_Meta_DestMACAddress_nxt		: std_logic;
200	
201	begin
202	
203		RX_DestMAC : entity PoC.mac_RX_DestMAC_Switch
204			generic map (
205				DEBUG								=> DEBUG,
206				MAC_ADDRESSES									=> INTERFACE_ADDRESSES,
207				MAC_ADDRESSE_MASKS						=> INTERFACE_MASKS
208			)
209			port map(
210				Clock													=> Clock,
211				Reset													=> Reset,
212	
213				In_Valid											=> Eth_RX_Valid,
214				In_Data												=> Eth_RX_Data,
215				In_SOF												=> Eth_RX_SOF,
216				In_EOF												=> Eth_RX_EOF,
217				In_Ack												=> Eth_RX_Ack,
218	
219				Out_Valid											=> DestEth_RX_Valid,
220				Out_Data											=> DestEth_RX_Data,
221				Out_SOF												=> DestEth_RX_SOF,
222				Out_EOF												=> DestEth_RX_EOF,
223				Out_Ack												=> SrcEth_RX_Ack,
224				Out_Meta_DestMACAddress_rst		=> SrcEth_RX_Meta_rst,
225				Out_Meta_DestMACAddress_nxt		=> SrcEth_RX_Meta_DestMACAddress_nxt,
226				Out_Meta_DestMACAddress_Data	=> DestEth_RX_Meta_DestMACAddress_Data
227			);
228	
229		genInterface : for i in MAC_CONFIG'range generate
230			constant FILTER_COUNT										: natural												:= getSourceFilterCount(MAC_CONFIG(i).SourceFilter);
231			constant FILTER_ADDRESSES								: T_NET_MAC_ADDRESS_VECTOR			:= getSourceFilterAddresses(MAC_CONFIG(i).SourceFilter(0 to FILTER_COUNT - 1));
232			constant FILTER_MASKS										: T_NET_MAC_ADDRESS_VECTOR			:= getSourceFilterMasks(MAC_CONFIG(i).SourceFilter(0 to FILTER_COUNT - 1));
233	
234			constant SWITCH_COUNT										: natural												:= getTypeSwitchCount(MAC_CONFIG(i).TypeSwitch);
235			constant SWITCH_TYPES										: T_NET_MAC_ETHERNETTYPE_VECTOR	:= MAC_CONFIG(i).TypeSwitch(0 to SWITCH_COUNT - 1);
236	
237			constant PORT_INDEX_FROM								: natural												:= calcPortIndex(MAC_CONFIG, i);
238			constant PORT_INDEX_TO									: natural												:= PORT_INDEX_FROM + SWITCH_COUNT - 1;
239	
240			signal SrcEth_RX_Valid									: std_logic;
241			signal SrcEth_RX_Data										: T_SLV_8;
242			signal SrcEth_RX_SOF										: std_logic;
243			signal SrcEth_RX_EOF										: std_logic;
244	
245	--		signal SrcEth_RX_Meta_SrcMACAddress_rst			: STD_LOGIC;
246	--		signal SrcEth_RX_Meta_SrcMACAddress_nxt			: STD_LOGIC;
247			signal SrcEth_RX_Meta_DestMACAddress_Data		: T_SLV_8;
248			signal SrcEth_RX_Meta_SrcMACAddress_Data		: T_SLV_8;
249	
250			signal EthEth_RX_Ack												: std_logic;
251			signal EthEth_RX_Meta_rst										: std_logic;
252			signal EthEth_RX_Meta_DestMACAddress_nxt		: std_logic;
253			signal EthEth_RX_Meta_SrcMACAddress_nxt			: std_logic;
254	
255		begin
256	--		assert FALSE report "Filter:      Count=" & INTEGER'image(FILTER_COUNT) severity NOTE;
257	--		assert FALSE report "PortIndex:   From="	& INTEGER'image(PORT_INDEX_FROM) & " to=" & INTEGER'image(PORT_INDEX_TO) severity NOTE;
258	
259			RX_SrcMAC : entity PoC.mac_RX_SrcMAC_Filter
260				generic map (
261					DEBUG								=> DEBUG,
262					MAC_ADDRESSES									=> FILTER_ADDRESSES,
263					MAC_ADDRESSE_MASKS						=> FILTER_MASKS
264				)
265				port map(
266					Clock													=> Clock,
267					Reset													=> Reset,
268	
269					In_Valid											=> DestEth_RX_Valid(i),
270					In_Data												=> DestEth_RX_Data(i),
271					In_SOF												=> DestEth_RX_SOF(i),
272					In_EOF												=> DestEth_RX_EOF(i),
273					In_Ack					 							=> SrcEth_RX_Ack	(i),
274					In_Meta_rst										=> SrcEth_RX_Meta_rst(i),
275					In_Meta_DestMACAddress_nxt		=> SrcEth_RX_Meta_DestMACAddress_nxt(i),
276					In_Meta_DestMACAddress_Data		=> DestEth_RX_Meta_DestMACAddress_Data(i),
277	
278					Out_Valid											=> SrcEth_RX_Valid,
279					Out_Data											=> SrcEth_RX_Data,
280					Out_SOF												=> SrcEth_RX_SOF,
281					Out_EOF												=> SrcEth_RX_EOF,
282					Out_Ack												=> EthEth_RX_Ack,
283					Out_Meta_rst									=> EthEth_RX_Meta_rst,
284					Out_Meta_DestMACAddress_nxt		=> EthEth_RX_Meta_DestMACAddress_nxt,
285					Out_Meta_DestMACAddress_Data	=> SrcEth_RX_Meta_DestMACAddress_Data,
286					Out_Meta_SrcMACAddress_nxt		=> EthEth_RX_Meta_SrcMACAddress_nxt,
287					Out_Meta_SrcMACAddress_Data		=> SrcEth_RX_Meta_SrcMACAddress_Data
288				);
289	
290			RX_EthType : entity PoC.mac_RX_Type_Switch
291				generic map (
292					DEBUG								=> DEBUG,
293					ETHERNET_TYPES								=> SWITCH_TYPES
294				)
295				port map(
296					Clock													=> Clock,
297					Reset													=> Reset,
298	
299					In_Valid											=> SrcEth_RX_Valid,
300					In_Data												=> SrcEth_RX_Data,
301					In_SOF												=> SrcEth_RX_SOF,
302					In_EOF												=> SrcEth_RX_EOF,
303					In_Ack												=> EthEth_RX_Ack,
304					In_Meta_rst										=> EthEth_RX_Meta_rst,
305					In_Meta_DestMACAddress_nxt		=> EthEth_RX_Meta_DestMACAddress_nxt,
306					In_Meta_DestMACAddress_Data		=> SrcEth_RX_Meta_DestMACAddress_Data,
307					In_Meta_SrcMACAddress_nxt			=> EthEth_RX_Meta_SrcMACAddress_nxt,
308					In_Meta_SrcMACAddress_Data		=> SrcEth_RX_Meta_SrcMACAddress_Data,
309	
310					Out_Valid											=> RX_Valid(PORT_INDEX_TO downto PORT_INDEX_FROM),
311					Out_Data											=> RX_Data(PORT_INDEX_TO downto PORT_INDEX_FROM),
312					Out_SOF												=> RX_SOF(PORT_INDEX_TO downto PORT_INDEX_FROM),
313					Out_EOF												=> RX_EOF(PORT_INDEX_TO downto PORT_INDEX_FROM),
314					Out_Ack												=> RX_Ack	(PORT_INDEX_TO downto PORT_INDEX_FROM),
315					Out_Meta_rst									=> RX_Meta_rst(PORT_INDEX_TO downto PORT_INDEX_FROM),
316					Out_Meta_DestMACAddress_nxt		=> RX_Meta_DestMACAddress_nxt(PORT_INDEX_TO downto PORT_INDEX_FROM),
317					Out_Meta_DestMACAddress_Data	=> RX_Meta_DestMACAddress_Data(PORT_INDEX_TO downto PORT_INDEX_FROM),
318					Out_Meta_SrcMACAddress_nxt		=> RX_Meta_SrcMACAddress_nxt(PORT_INDEX_TO downto PORT_INDEX_FROM),
319					Out_Meta_SrcMACAddress_Data		=> RX_Meta_SrcMACAddress_Data(PORT_INDEX_TO downto PORT_INDEX_FROM),
320					Out_Meta_EthType							=> RX_Meta_EthType(PORT_INDEX_TO downto PORT_INDEX_FROM)
321				);
322	
323			-- Ethernet Type prepender
324			TX_EthType : entity PoC.mac_TX_Type_Prepender
325				generic map (
326					ETHERNET_TYPES								=> SWITCH_TYPES
327				)
328				port map(
329					Clock													=> Clock,
330					Reset													=> Reset,
331	
332					In_Valid											=> TX_Valid(PORT_INDEX_TO downto PORT_INDEX_FROM),
333					In_Data												=> TX_Data(PORT_INDEX_TO downto PORT_INDEX_FROM),
334					In_SOF												=> TX_SOF(PORT_INDEX_TO downto PORT_INDEX_FROM),
335					In_EOF												=> TX_EOF(PORT_INDEX_TO downto PORT_INDEX_FROM),
336					In_Ack												=> TX_Ack	(PORT_INDEX_TO downto PORT_INDEX_FROM),
337					In_Meta_rst										=> TX_Meta_rst(PORT_INDEX_TO downto PORT_INDEX_FROM),
338					In_Meta_DestMACAddress_nxt		=> TX_Meta_DestMACAddress_nxt(PORT_INDEX_TO downto PORT_INDEX_FROM),
339					In_Meta_DestMACAddress_Data		=> TX_Meta_DestMACAddress_Data(PORT_INDEX_TO downto PORT_INDEX_FROM),
340	
341					Out_Valid											=> EthType_TX_Valid(i),
342					Out_Data											=> EthType_TX_Data(i),
343					Out_SOF												=> EthType_TX_SOF(i),
344					Out_EOF												=> EthType_TX_EOF(i),
345					Out_Ack												=> SrcEth_TX_Ack	(i),
346					Out_Meta_rst									=> SrcEth_TX_Meta_rst(i),
347					Out_Meta_DestMACAddress_nxt		=> SrcEth_TX_Meta_DestMACAddress_nxt(i),
348					Out_Meta_DestMACAddress_Data	=> EthType_TX_Meta_DestMACAddress_Data(i)
349				);
350		end generate;
351	
352		-- Ethernet SourceMAC prepender
353		TX_SrcMAC : entity PoC.mac_TX_SrcMAC_Prepender
354			generic map (
355				MAC_ADDRESSES									=> INTERFACE_ADDRESSES
356			)
357			port map(
358				Clock													=> Clock,
359				Reset													=> Reset,
360	
361				In_Valid											=> EthType_TX_Valid,
362				In_Data												=> EthType_TX_Data,
363				In_SOF												=> EthType_TX_SOF,
364				In_EOF												=> EthType_TX_EOF,
365				In_Ack												=> SrcEth_TX_Ack,
366				In_Meta_rst										=> SrcEth_TX_Meta_rst,
367				In_Meta_DestMACAddress_nxt		=> SrcEth_TX_Meta_DestMACAddress_nxt,
368				In_Meta_DestMACAddress_Data		=> EthType_TX_Meta_DestMACAddress_Data,
369	
370				Out_Valid											=> SrcEth_TX_Valid,
371				Out_Data											=> SrcEth_TX_Data,
372				Out_SOF												=> SrcEth_TX_SOF,
373				Out_EOF												=> SrcEth_TX_EOF,
374				Out_Ack												=> DestEth_TX_Ack,
375				Out_Meta_rst									=> DestEth_TX_Meta_rst,
376				Out_Meta_DestMACAddress_nxt		=> DestEth_TX_Meta_DestMACAddress_nxt,
377				Out_Meta_DestMACAddress_Data	=> SrcEth_TX_Meta_DestMACAddress_Data
378			);
379	
380		-- Ethernet SourceMAC prepender
381		TX_DestMAC : entity PoC.mac_TX_DestMAC_Prepender
382			port map(
383				Clock													=> Clock,
384				Reset													=> Reset,
385	
386				In_Valid											=> SrcEth_TX_Valid,
387				In_Data												=> SrcEth_TX_Data,
388				In_SOF												=> SrcEth_TX_SOF,
389				In_EOF												=> SrcEth_TX_EOF,
390				In_Ack												=> DestEth_TX_Ack,
391	
392				In_Meta_rst										=> DestEth_TX_Meta_rst,
393				In_Meta_DestMACAddress_nxt		=> DestEth_TX_Meta_DestMACAddress_nxt,
394				In_Meta_DestMACAddress_Data		=> SrcEth_TX_Meta_DestMACAddress_Data,
395	
396				Out_Valid											=> Eth_TX_Valid,
397				Out_Data											=> Eth_TX_Data,
398				Out_SOF												=> Eth_TX_SOF,
399				Out_EOF												=> Eth_TX_EOF,
400				Out_Ack												=> Eth_TX_Ack
401			);
