322	
323			FSMPool_BCRcv_Clear										<= '0';
324			FSMPool_BCRcv_Address_rst							<= '0';
325			FSMPool_BCRcv_SenderMACAddress_nxt		<= '0';
326			FSMPool_BCRcv_SenderIPv4Address_nxt		<= '0';
327			FSMPool_BCRcv_TargetIPv4Address_nxt		<= '0';
328	
329			FSMPool_IPPool_Lookup									<= '0';
330			FSMPool_IPPool_IPv4Address_Data				<= BCRcv_TargetIPv4Address_Data;
331	
332			FSMPool_UCRsp_SendResponse						<= '0';
333			FSMPool_UCRsp_SenderMACAddress_Data		<= MACSeq1_SenderMACAddress_Data;
334			FSMPool_UCRsp_SenderIPv4Address_Data	<= BCRcv_TargetIPv4Address_Data;
335			FSMPool_UCRsp_TargetMACAddress_Data		<= BCRcv_SenderMACAddress_Data;
336			FSMPool_UCRsp_TargetIPv4Address_Data	<= BCRcv_SenderIPv4Address_Data;
337	
338			case FSMPool_State is
339				when ST_IDLE =>
340					if (BCRcv_RequestReceived = '1') then
341						FSMPool_IPPool_Lookup									<= '1';
342						FSMPool_BCRcv_TargetIPv4Address_nxt		<= IPPool_IPv4Address_nxt;
343	
344						FSMPool_NextState											<= ST_IPPOOL_WAIT;
345					elsif (IPPool_Announce_l = '1') then
346	--					FSMPool_UCRsp_SendResponse						<= '1';
347	
348	--					FSMPool_NextState											<= ST_SEND_ANNOUNCE;
349					end if;
350	
351				when ST_IPPOOL_WAIT =>
352					FSMPool_BCRcv_TargetIPv4Address_nxt			<= IPPool_IPv4Address_nxt;
353	
354					if (IPPool_PoolResult = CACHE_RESULT_HIT) then
355						FSMPool_BCRcv_Address_rst							<= '1';
356						FSMPool_MACSeq1_SenderMACAddress_rst	<= '1';
357						FSMPool_UCRsp_SendResponse						<= '1';
358	
359						FSMPool_NextState											<= ST_SEND_RESPONSE;
360					elsif (IPPool_PoolResult = CACHE_RESULT_MISS) then
361						FSMPool_BCRcv_Clear										<= '1';
362						FSMPool_NextState											<= ST_IDLE;
363					end if;
364	
365				when ST_SEND_RESPONSE =>
366					FSMPool_BCRcv_Address_rst								<= UCRsp_Address_rst;
367					FSMPool_BCRcv_SenderMACAddress_nxt			<= UCRsp_TargetMACAddress_nxt;
368					FSMPool_BCRcv_SenderIPv4Address_nxt			<= UCRsp_TargetIPv4Address_nxt;
369					FSMPool_MACSeq1_SenderMACAddress_nxt		<= UCRsp_SenderMACAddress_nxt;
370					FSMPool_BCRcv_TargetIPv4Address_nxt			<= UCRsp_SenderIPv4Address_nxt;
371	
372					if (UCRsp_Complete = '1') then
373						FSMPool_BCRcv_Clear							<= '1';
374						FSMPool_NextState								<= ST_IDLE;
375					end if;
376	
377				when ST_SEND_ANNOUNCE =>
378					if (UCRsp_Complete = '1') then
379						IPPool_Announced_i							<= '1';
380						FSMPool_BCRcv_Clear							<= '1';
381	
382						FSMPool_NextState								<= ST_IDLE;
383					end if;
384	
385				when ST_ERROR =>
386					null;
387	
388			end case;
389		end process;
