478		MACSeq2 : entity PoC.misc_Sequencer
479			generic map (
480				INPUT_BITS						=> 48,
481				OUTPUT_BITS						=> 8,
482				REGISTERED						=> FALSE
483			)
484			port map (
485				Clock									=> Clock,
486				Reset									=> Reset,
487	
488				Input									=> to_slv(INTERFACE_MACADDRESS),
489				rst										=> FSMCache_MACSeq2_SenderMACAddress_rst,
