495		IPSeq2 : entity PoC.misc_Sequencer
496			generic map (
497				INPUT_BITS						=> 32,
498				OUTPUT_BITS						=> 8,
499				REGISTERED						=> FALSE
500			)
501			port map (
502				Clock									=> Clock,
503				Reset									=> Reset,
504	
505				Input									=> to_slv(INITIAL_IPV4ADDRESSES(0)),
506				rst										=> FSMCache_IPSeq2_SenderIPv4Address_rst,
507				rev										=> '1',
508				nxt										=> FSMCache_IPSeq2_SenderIPv4Address_nxt,
509				Output								=> IPSeq2_SenderIPv4Address_Data
510			);
511	
512		process(Clock)
513		begin
514			if rising_edge(Clock) then
515				if (Reset = '1') then
516					FSMCache_State		<= ST_IDLE;
517				else
518					FSMCache_State		<= FSMCache_NextState;
519				end if;
520			end if;
521		end process;
522	
523		process(FSMCache_State,
524						IPCache_Lookup, IPCache_IPv4Address_Data,	IPCache_MACAddress_rst, IPCache_MACAddress_nxt,
525						MACSeq2_SenderMACAddress_Data, IPSeq2_SenderIPv4Address_Data, ARPReq_Timeout,
526						UCRcv_Error, UCRcv_ResponseReceived, UCRcv_SenderIPv4Address_Data, UCRcv_SenderMACAddress_Data, UCRcv_TargetIPv4Address_Data, UCRcv_TargetMACAddress_Data,
527						ARPCache_Status, ARPCache_CacheResult, ARPCache_IPv4Address_rst, ARPCache_IPv4Address_nxt, ARPCache_MACAddress_Data, ARPCache_NewMACAddress_nxt, ARPCache_NewIPv4Address_nxt,
528						BCReq_Address_rst, BCReq_SenderMACAddress_nxt, BCReq_SenderIPv4Address_nxt, BCReq_TargetMACAddress_nxt, BCReq_TargetIPv4Address_nxt, BCReq_Complete)
529		begin
530			FSMCache_NextState													<= FSMCache_State;
531	
532			IPCache_IPv4Address_rst											<= '0';
533			IPCache_IPv4Address_nxt											<= '0';
534	
535			IPCache_Valid																<= '0';
536			IPCache_MACAddress_Data											<= ARPCache_MACAddress_Data;
537	
538			FSMCache_ARPCache_Command										<= NET_ARP_ARPCACHE_CMD_NONE;
539			FSMCache_ARPCache_NewMACAddress_Data				<= UCRcv_SenderMACAddress_Data;
540			FSMCache_ARPCache_NewIPv4Address_Data				<= UCRcv_SenderIPv4Address_Data;
541	
542			FSMCache_MACSeq2_SenderMACAddress_rst				<= '0';
543			FSMCache_MACSeq2_SenderMACAddress_nxt				<= '0';
544			FSMCache_IPSeq2_SenderIPv4Address_rst				<= '0';
545			FSMCache_IPSeq2_SenderIPv4Address_nxt				<= '0';
546	
547			FSMCache_ARPReq_TimeoutCounter_rst					<= '1';
548	
549			FSMCache_ARPCache_Lookup										<= '0';
550			FSMCache_ARPCache_IPv4Address_Data					<= IPCache_IPv4Address_Data;
551			FSMCache_ARPCache_MACAddress_rst						<= IPCache_MACAddress_rst;
552			FSMCache_ARPCache_MACAddress_nxt						<= IPCache_MACAddress_nxt;
553	
554			FSMCache_BCReq_SendRequest									<= '0';
555			FSMCache_BCReq_SenderMACAddress_Data				<= MACSeq2_SenderMACAddress_Data;
556			FSMCache_BCReq_SenderIPv4Address_Data				<= IPSeq2_SenderIPv4Address_Data;
557			FSMCache_BCReq_TargetMACAddress_Data				<= x"00";
558			FSMCache_BCReq_TargetIPv4Address_Data				<= IPCache_IPv4Address_Data;
559	
560			FSMCache_UCRcv_Clear												<= UCRcv_ResponseReceived;		-- discard all ARP packets, which are not requested / expected
561			FSMCache_UCRcv_Address_rst									<= '0';
562			FSMCache_UCRcv_SenderMACAddress_nxt					<= '0';
563			FSMCache_UCRcv_SenderIPv4Address_nxt				<= '0';
564			FSMCache_UCRcv_TargetMACAddress_nxt					<= '0';		-- default assignment for unsed metadata TargetMACAddress
565			FSMCache_UCRcv_TargetIPv4Address_nxt				<= '0';		-- default assignment for unsed metadata TargetIPv4Address
566	
567			case FSMCache_State is
568				when ST_IDLE =>
569					IPCache_IPv4Address_rst									<= '1';
570	
571					if (IPCache_Lookup = '1') then
572						FSMCache_NextState										<= ST_CACHE;
573					end if;
574	
575				when ST_CACHE =>
576					FSMCache_ARPCache_Lookup								<= '1';
577					IPCache_IPv4Address_rst									<= ARPCache_IPv4Address_rst;
578					IPCache_IPv4Address_nxt									<= ARPCache_IPv4Address_nxt;
579	
580					if (ARPCache_CacheResult = CACHE_RESULT_MISS) then
581						FSMCache_NextState										<= ST_SEND_BROADCAST_REQUEST;
582					else
583						FSMCache_NextState										<= ST_CACHE_WAIT;
584					end if;
585	
586				when ST_CACHE_WAIT =>
587					IPCache_IPv4Address_rst									<= ARPCache_IPv4Address_rst;
588					IPCache_IPv4Address_nxt									<= ARPCache_IPv4Address_nxt;
589	
590					if (ARPCache_CacheResult = CACHE_RESULT_HIT) then
591						FSMCache_NextState										<= ST_READ_CACHE;
592					elsif (ARPCache_CacheResult = CACHE_RESULT_MISS) then
593						FSMCache_NextState										<= ST_SEND_BROADCAST_REQUEST;
594					end if;
595	
596				when ST_READ_CACHE =>
597					IPCache_IPv4Address_rst									<= '1';
598					IPCache_Valid														<= '1';
599	
600					FSMCache_ARPCache_MACAddress_rst				<= IPCache_MACAddress_rst;
601					FSMCache_ARPCache_MACAddress_nxt				<= IPCache_MACAddress_nxt;
602	
603					if (IPCache_Lookup = '1') then
604						FSMCache_NextState										<= ST_CACHE;
605					end if;
606	
607				when ST_SEND_BROADCAST_REQUEST =>
608					FSMCache_MACSeq2_SenderMACAddress_rst		<= '1';
609					FSMCache_IPSeq2_SenderIPv4Address_rst		<= '1';
610					FSMCache_BCReq_SendRequest							<= '1';
611	
612					IPCache_IPv4Address_rst									<= BCReq_Address_rst;
613					IPCache_IPv4Address_nxt									<= BCReq_TargetIPv4Address_nxt;
614	
615					FSMCache_NextState											<= ST_SEND_BROADCAST_REQUEST_WAIT;
616	
617				when ST_SEND_BROADCAST_REQUEST_WAIT =>
618					FSMCache_MACSeq2_SenderMACAddress_rst		<= BCReq_Address_rst;
619					FSMCache_MACSeq2_SenderMACAddress_nxt		<= BCReq_SenderMACAddress_nxt;
620					FSMCache_IPSeq2_SenderIPv4Address_rst		<= BCReq_Address_rst;
621					FSMCache_IPSeq2_SenderIPv4Address_nxt		<= BCReq_SenderIPv4Address_nxt;
622	
623					IPCache_IPv4Address_rst									<= BCReq_Address_rst;
624					IPCache_IPv4Address_nxt									<= BCReq_TargetIPv4Address_nxt;
625	
626					if (BCReq_Complete = '1') then
627						FSMCache_NextState										<= ST_WAIT_FOR_UNICAST_RESPONSE;
628					end if;
629	
630				when ST_WAIT_FOR_UNICAST_RESPONSE =>
631					FSMCache_UCRcv_Clear										<= '0';
632					FSMCache_ARPReq_TimeoutCounter_rst			<= '0';
633					-- TODO: check received ARP packet data with ethernet metadata
634	
635					if (UCRcv_Error = '1') then
636						-- FIXME: error handling
637						FSMCache_NextState										<= ST_ERROR;
638					elsif (UCRcv_ResponseReceived = '1') then
639						FSMCache_ARPCache_Command							<= NET_ARP_ARPCACHE_CMD_ADD;
640						FSMCache_UCRcv_SenderMACAddress_nxt		<= ARPCache_NewMACAddress_nxt;
641						FSMCache_UCRcv_SenderIPv4Address_nxt	<= ARPCache_NewIPv4Address_nxt;
642	
643						FSMCache_NextState										<= ST_UPDATE_CACHE;
644					elsif (ARPReq_Timeout = '1') then
645						-- FIXME: error handling
646	--					FSMCache_NextState										<= ST_ERROR;
647						FSMCache_NextState										<= ST_SEND_BROADCAST_REQUEST;
648					end if;
649	
650				when ST_UPDATE_CACHE =>
651					FSMCache_UCRcv_Clear										<= '0';
652					FSMCache_UCRcv_SenderMACAddress_nxt			<= ARPCache_NewMACAddress_nxt;
653					FSMCache_UCRcv_SenderIPv4Address_nxt		<= ARPCache_NewIPv4Address_nxt;
654	
655					if (ARPCache_Status = NET_ARP_ARPCACHE_STATUS_UPDATE_COMPLETE) then
656						FSMCache_UCRcv_Clear									<= '1';
657						IPCache_IPv4Address_rst								<= '1';
658	
659						FSMCache_NextState										<= ST_CACHE;
660					end if;
661	
662				when ST_ERROR =>
663					-- FIXME: error handling
664					FSMCache_NextState											<= ST_IDLE;
665	
666			end case;
667		end process;
668	
669		-- ARP request expiration timer
670		process(Clock)
671		begin
672			if rising_edge(Clock) then
673				if (FSMCache_ARPReq_TimeoutCounter_rst = '1') then
674					ARPReq_TimeoutCounter_s		<= to_signed(ARPREQ_TIMEOUTCOUNTER_MAX, ARPReq_TimeoutCounter_s'length);
675				else
676					ARPReq_TimeoutCounter_s		<= ARPReq_TimeoutCounter_s - 1;
677				end if;
678			end if;
679		end process;
680	
681		ARPReq_Timeout			<= ARPReq_TimeoutCounter_s(ARPReq_TimeoutCounter_s'high);
