722				TAG_BYTE_ORDER							=> BIG_ENDIAN,
723				DATA_BYTE_ORDER							=> BIG_ENDIAN,
724				INITIAL_CACHE_CONTENT				=> INITIAL_ARPCACHE_CONTENT
725			)
726			port map (
727				Clock												=> Clock,
728				Reset												=> Reset,
729	
730				Command											=> FSMCache_ARPCache_Command,
731				Status											=> ARPCache_Status,
732				NewMACAddress_nxt						=> ARPCache_NewMACAddress_nxt,
733				NewMACAddress_Data					=> FSMCache_ARPCache_NewMACAddress_Data,
734				NewIPv4Address_nxt					=> ARPCache_NewIPv4Address_nxt,
735				NewIPv4Address_Data					=> FSMCache_ARPCache_NewIPv4Address_Data,
736	
737				Lookup											=> FSMCache_ARPCache_Lookup,
738				IPv4Address_rst							=> ARPCache_IPv4Address_rst,
739				IPv4Address_nxt							=> ARPCache_IPv4Address_nxt,
740				IPv4Address_Data						=> FSMCache_ARPCache_IPv4Address_Data,
741	
742				CacheResult									=> ARPCache_CacheResult,
743				MACAddress_rst							=> FSMCache_ARPCache_MACAddress_rst,
744				MACAddress_nxt							=> FSMCache_ARPCache_MACAddress_nxt,
745				MACAddress_Data							=> ARPCache_MACAddress_Data
746			);
747	
748		BCReq : entity PoC.arp_BroadCast_Requester
749	--		generic map (
750	--
751	--		)
752			port map (
753				Clock													=> Clock,
754				Reset													=> Reset,
755	
756				SendRequest										=> FSMCache_BCReq_SendRequest,
757				Complete											=> BCReq_Complete,
758				Address_rst										=> BCReq_Address_rst,
759				SenderMACAddress_nxt					=> BCReq_SenderMACAddress_nxt,
760				SenderMACAddress_Data					=> FSMCache_BCReq_SenderMACAddress_Data,			-- self
761				SenderIPv4Address_nxt					=> BCReq_SenderIPv4Address_nxt,
762				SenderIPv4Address_Data				=> FSMCache_BCReq_SenderIPv4Address_Data,			-- self
763				TargetMACAddress_nxt					=> BCReq_TargetMACAddress_nxt,
764				TargetMACAddress_Data					=> FSMCache_BCReq_TargetMACAddress_Data,			-- broadcast + request for mac-to-ip mapping
765				TargetIPv4Address_nxt					=> BCReq_TargetIPv4Address_nxt,
766				TargetIPv4Address_Data				=> FSMCache_BCReq_TargetIPv4Address_Data,			-- broadcast + request for mac-to-ip mapping
767	
768				TX_Valid											=> BCReq_TX_Valid,
769				TX_Data												=> BCReq_TX_Data,
770				TX_SOF												=> BCReq_TX_SOF,
771				TX_EOF												=> BCReq_TX_EOF,
772				TX_Ack												=> BCReq_TX_Ack,
773				TX_Meta_DestMACAddress_rst		=> BCReq_TX_Meta_DestMACAddress_rst,
774				TX_Meta_DestMACAddress_nxt		=> BCReq_TX_Meta_DestMACAddress_nxt,
775				TX_Meta_DestMACAddress_Data		=> BCReq_TX_Meta_DestMACAddress_Data
776			);
777	
778		blkStmMux : block
779			constant LLMUX_PORT_BCREQ		: natural					:= 0;
780			constant LLMUX_PORT_UCRSP		: natural					:= 1;
781			constant LLMUX_PORTS				: positive				:= 2;
782	
783			constant META_RST_BIT				: natural					:= 0;
784			constant META_DEST_NXT_BIT	: natural					:= 1;
785	
786			constant META_BITS					: positive				:= 8;
787			constant META_REV_BITS			: positive				:= 2;
788	
789	
790			signal Temp_Meta						: T_SLVV_48(LLMUX_PORTS - 1 downto 0);
791			signal Temp_Meta2						: T_SLV_48;
792	
793			signal StmMux_In_Valid			: std_logic_vector(LLMUX_PORTS - 1 downto 0);
794			signal StmMux_In_Data				: T_SLM(LLMUX_PORTS - 1 downto 0, T_SLV_8'range)								:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
795			signal StmMux_In_Meta				: T_SLM(LLMUX_PORTS - 1 downto 0, META_BITS - 1 downto 0)				:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
796			signal StmMux_In_Meta_rev		: T_SLM(LLMUX_PORTS - 1 downto 0, META_REV_BITS - 1 downto 0)		:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
797			signal StmMux_In_SOF				: std_logic_vector(LLMUX_PORTS - 1 downto 0);
798			signal StmMux_In_EOF				: std_logic_vector(LLMUX_PORTS - 1 downto 0);
799			signal StmMux_In_Ack				: std_logic_vector(LLMUX_PORTS - 1 downto 0);
800	
801			signal StmMux_Out_Meta			: std_logic_vector(META_BITS - 1 downto 0);
802			signal StmMux_Out_Meta_rev	: std_logic_vector(META_REV_BITS - 1 downto 0);
803	
804		begin
805	
806			-- StmMux Port 0 - broadcast requester
807			StmMux_In_Valid(LLMUX_PORT_BCREQ)				<= BCReq_TX_Valid;
808			assign_row(StmMux_In_Data, BCReq_TX_Data,	LLMUX_PORT_BCREQ);
809			StmMux_In_SOF(LLMUX_PORT_BCREQ)					<= BCReq_TX_SOF;
810			StmMux_In_EOF(LLMUX_PORT_BCREQ)					<= BCReq_TX_EOF;
811			BCReq_TX_Ack														<= StmMux_In_Ack	(LLMUX_PORT_BCREQ);
812			assign_row(StmMux_In_Meta, BCReq_TX_Meta_DestMACAddress_Data, LLMUX_PORT_BCREQ);
813			BCReq_TX_Meta_DestMACAddress_rst				<= StmMux_In_Meta_rev(LLMUX_PORT_BCREQ, META_RST_BIT);
814			BCReq_TX_Meta_DestMACAddress_nxt				<= StmMux_In_Meta_rev(LLMUX_PORT_BCREQ, META_DEST_NXT_BIT);
815	
816			-- StmMux Port 1 - unicast responder
817			StmMux_In_Valid(LLMUX_PORT_UCRSP)				<= UCRsp_TX_Valid;
818			assign_row(StmMux_In_Data, UCRsp_TX_Data,	LLMUX_PORT_UCRSP);
819			StmMux_In_SOF(LLMUX_PORT_UCRSP)					<= UCRsp_TX_SOF;
820			StmMux_In_EOF(LLMUX_PORT_UCRSP)					<= UCRsp_TX_EOF;
821			UCRsp_TX_Ack														<= StmMux_In_Ack	(LLMUX_PORT_UCRSP);
822			UCRsp_TX_Meta_DestMACAddress_rst				<= StmMux_In_Meta_rev(LLMUX_PORT_UCRSP, META_RST_BIT);
823			UCRsp_TX_Meta_DestMACAddress_nxt				<= StmMux_In_Meta_rev(LLMUX_PORT_UCRSP, META_DEST_NXT_BIT);
824			assign_row(StmMux_In_Meta, UCRsp_TX_Meta_DestMACAddress_Data, LLMUX_PORT_UCRSP);
825	
826			StmMux : entity PoC.stream_Mux
827				generic map (
828					PORTS									=> LLMUX_PORTS,
829					DATA_BITS							=> Eth_UC_TX_Data'length,
830					META_BITS							=> META_BITS,
831					META_REV_BITS					=> META_REV_BITS
832				)
833				port map (
834					Clock									=> Clock,
835					Reset									=> Reset,
836	
837					In_Valid							=> StmMux_In_Valid,
838					In_Data								=> StmMux_In_Data,
839					In_Meta								=> StmMux_In_Meta,
840					In_Meta_rev						=> StmMux_In_Meta_rev,
841					In_SOF								=> StmMux_In_SOF,
842					In_EOF								=> StmMux_In_EOF,
843					In_Ack								=> StmMux_In_Ack,
844	
845					Out_Valid							=> Eth_UC_TX_Valid,
846					Out_Data							=> Eth_UC_TX_Data,
847					Out_Meta							=> StmMux_Out_Meta,
848					Out_Meta_rev					=> StmMux_Out_Meta_rev,
849					Out_SOF								=> Eth_UC_TX_SOF,
850					Out_EOF								=> Eth_UC_TX_EOF,
851					Out_Ack								=> Eth_UC_TX_Ack
852				);
853	
854			StmMux_Out_Meta_rev(META_RST_BIT)				<= Eth_UC_TX_Meta_rst;
855			StmMux_Out_Meta_rev(META_DEST_NXT_BIT)	<= Eth_UC_TX_Meta_DestMACAddress_nxt;
856			Eth_UC_TX_Meta_DestMACAddress_Data			<= StmMux_Out_Meta(Eth_UC_TX_Meta_DestMACAddress_Data'range);
857		end block;
858	end architecture;
859

