115	architecture rtl of ipv4_Wrapper is
116		constant IPV4_SWITCH_PORTS								: positive				:= PACKET_TYPES'length;
117	
118		constant TXSTMMUX_META_STREAMID_SRCADR		: natural					:= 0;
119		constant TXSTMMUX_META_STREAMID_DESTADR		: natural					:= 1;
120		constant TXSTMMUX_META_STREAMID_LENGTH		: natural					:= 2;
121		constant TXSTMMUX_META_STREAMID_PROTOCOL			: natural					:= 3;
122	
123		constant TXSTMMUX_META_BITS								: T_POSVEC				:= (
124			TXSTMMUX_META_STREAMID_SRCADR			=> 8,
125			TXSTMMUX_META_STREAMID_DESTADR		=> 8,
126			TXSTMMUX_META_STREAMID_LENGTH			=> 16,
127			TXSTMMUX_META_STREAMID_PROTOCOL		=> 8
128		);
129	
130		constant TXSTMMUX_META_RST_BIT						: natural					:= 0;
131		constant TXSTMMUX_META_SRC_NXT_BIT				: natural					:= 1;
132		constant TXSTMMUX_META_DEST_NXT_BIT				: natural					:= 2;
133	
134		constant TXSTMMUX_META_REV_BITS						: natural					:= 3;
135	
136		signal StmMux_In_Valid										: std_logic_vector(IPV4_SWITCH_PORTS - 1 downto 0);
137		signal StmMux_In_Data											: T_SLM(IPV4_SWITCH_PORTS - 1 downto 0, T_SLV_8'range)													:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
138		signal StmMux_In_Meta											: T_SLM(IPV4_SWITCH_PORTS - 1 downto 0, isum(TXSTMMUX_META_BITS) - 1 downto 0)	:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
139		signal StmMux_In_Meta_rev									: T_SLM(IPV4_SWITCH_PORTS - 1 downto 0, TXSTMMUX_META_REV_BITS - 1 downto 0)		:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
140		signal StmMux_In_SOF											: std_logic_vector(IPV4_SWITCH_PORTS - 1 downto 0);
141		signal StmMux_In_EOF											: std_logic_vector(IPV4_SWITCH_PORTS - 1 downto 0);
142		signal StmMux_In_Ack											: std_logic_vector(IPV4_SWITCH_PORTS - 1 downto 0);
143	
144		signal TX_StmMux_Valid										: std_logic;
145		signal TX_StmMux_Data											: T_SLV_8;
146		signal TX_StmMux_Meta											: std_logic_vector(isum(TXSTMMUX_META_BITS) - 1 downto 0);
147		signal TX_StmMux_Meta_rev									: std_logic_vector(TXSTMMUX_META_REV_BITS - 1 downto 0);
148		signal TX_StmMux_SOF											: std_logic;
149		signal TX_StmMux_EOF											: std_logic;
150		signal TX_StmMux_SrcIPv4Address_Data			: T_SLV_8;
151		signal TX_StmMux_DestIPv4Address_Data			: T_SLV_8;
152		signal TX_StmMux_Length										: T_SLV_16;
153		signal TX_StmMux_Protocol									: T_SLV_8;
154	
155		signal IPv4_TX_Ack												: std_logic;
156		signal IPv4_TX_Meta_rst										: std_logic;
157		signal IPv4_TX_Meta_SrcIPv4Address_nxt		: std_logic;
158		signal IPv4_TX_Meta_DestIPv4Address_nxt		: std_logic;
159	
160		signal IPv4_RX_Valid											: std_logic;
161		signal IPv4_RX_Data												: T_SLV_8;
162		signal IPv4_RX_SOF												: std_logic;
163		signal IPv4_RX_EOF												: std_logic;
164	
165		signal IPv4_RX_Meta_SrcMACAddress_Data		: T_SLV_8;
166		signal IPv4_RX_Meta_DestMACAddress_Data		: T_SLV_8;
167		signal IPv4_RX_Meta_EthType								: T_SLV_16;
168		signal IPv4_RX_Meta_SrcIPv4Address_Data		: T_SLV_8;
169		signal IPv4_RX_Meta_DestIPv4Address_Data	: T_SLV_8;
170		signal IPv4_RX_Meta_Length								: T_SLV_16;
171		signal IPv4_RX_Meta_Protocol							: T_SLV_8;
172	
173		constant STMDEMUX_META_RST_BIT						: natural					:= 0;
174		constant STMDEMUX_META_MACSRC_NXT_BIT			: natural					:= 1;
175		constant STMDEMUX_META_MACDEST_NXT_BIT		: natural					:= 2;
176		constant STMDEMUX_META_IPV4SRC_NXT_BIT		: natural					:= 3;
177		constant STMDEMUX_META_IPV4DEST_NXT_BIT		: natural					:= 4;
178	
179		constant STMDEMUX_META_STREAMID_SRCMAC		: natural					:= 0;
180		constant STMDEMUX_META_STREAMID_DESTMAC		: natural					:= 1;
181		constant STMDEMUX_META_STREAMID_ETHTYPE		: natural					:= 2;
182		constant STMDEMUX_META_STREAMID_SRCIP			: natural					:= 3;
183		constant STMDEMUX_META_STREAMID_DESTIP		: natural					:= 4;
184		constant STMDEMUX_META_STREAMID_LENGTH		: natural					:= 5;
185		constant STMDEMUX_META_STREAMID_PROTO			: natural					:= 6;
186	
187		constant STMDEMUX_DATA_BITS								: natural					:= 8;							--
188		constant STMDEMUX_META_BITS								: T_POSVEC				:= (
189			STMDEMUX_META_STREAMID_SRCMAC		=> 8,
190			STMDEMUX_META_STREAMID_DESTMAC 	=> 8,
191			STMDEMUX_META_STREAMID_ETHTYPE 	=> 16,
192			STMDEMUX_META_STREAMID_SRCIP			=> 8,
193			STMDEMUX_META_STREAMID_DESTIP		=> 8,
194			STMDEMUX_META_STREAMID_LENGTH		=> 16,
195			STMDEMUX_META_STREAMID_PROTO			=> 8
196		);
197		constant STMDEMUX_META_REV_BITS							: natural					:= 5;							-- sum over all control bits (rst, nxt, nxt, nxt, nxt)
198	
199		signal RX_StmDeMux_Ack												: std_logic;
200		signal RX_StmDeMux_Meta_rst									: std_logic;
201		signal RX_StmDeMux_Meta_SrcMACAddress_nxt		: std_logic;
202		signal RX_StmDeMux_Meta_DestMACAddress_nxt		: std_logic;
203		signal RX_StmDeMux_Meta_SrcIPv4Address_nxt		: std_logic;
204		signal RX_StmDeMux_Meta_DestIPv4Address_nxt	: std_logic;
205	
206		signal RX_StmDeMux_MetaIn										: std_logic_vector(isum(STMDEMUX_META_BITS) - 1 downto 0);
207		signal RX_StmDeMux_MetaIn_rev								: std_logic_vector(STMDEMUX_META_REV_BITS - 1 downto 0);
208		signal RX_StmDeMux_Data											: T_SLM(IPV4_SWITCH_PORTS - 1 downto 0, STMDEMUX_DATA_BITS - 1 downto 0)				:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
209		signal RX_StmDeMux_MetaOut										: T_SLM(IPV4_SWITCH_PORTS - 1 downto 0, isum(STMDEMUX_META_BITS) - 1 downto 0)	:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
210		signal RX_StmDeMux_MetaOut_rev								: T_SLM(IPV4_SWITCH_PORTS - 1 downto 0, STMDEMUX_META_REV_BITS - 1 downto 0)		:= (others => (others => 'Z'));		-- necessary default assignment 'Z' to get correct simulation results (iSIM, vSIM, ghdl/gtkwave)
211	
212		signal StmDeMux_Control											: std_logic_vector(IPV4_SWITCH_PORTS - 1 downto 0);
213	
214	begin
215	-- =============================================================================
216	-- TX Path
217	-- =============================================================================
218		genTXStmBuf : for i in 0 to IPV4_SWITCH_PORTS - 1 generate
219			constant TXSTMBUF_META_STREAMID_SRCADR		: natural					:= 0;
220			constant TXSTMBUF_META_STREAMID_DESTADR		: natural					:= 1;
221			constant TXSTMBUF_META_STREAMID_LENGTH		: natural					:= 2;
222	
223			constant TXSTMBUF_META_BITS								: T_POSVEC				:= (
224				TXSTMBUF_META_STREAMID_SRCADR				=> 8,
225				TXSTMBUF_META_STREAMID_DESTADR			=> 8,
226				TXSTMBUF_META_STREAMID_LENGTH				=> 16
227			);
228	
229			constant TXSTMBUF_META_FIFO_DEPTHS				: T_POSVEC				:= (
230				TXSTMBUF_META_STREAMID_SRCADR				=> 4,
231				TXSTMBUF_META_STREAMID_DESTADR			=> 4,
232				TXSTMBUF_META_STREAMID_LENGTH				=> 1
233			);
234	
235			signal StmBuf_DataOut											: T_SLV_8;
236	--		signal Meta_rst														: STD_LOGIC;
237			signal StmBuf_MetaIn_nxt									: std_logic_vector(TXSTMBUF_META_BITS'length - 1 downto 0);
238			signal StmBuf_MetaIn_Data									: std_logic_vector(isum(TXSTMBUF_META_BITS) - 1 downto 0);
239	
240			signal StmBuf_Meta_rst										: std_logic;
241			signal StmBuf_MetaOut_nxt									: std_logic_vector(TXSTMBUF_META_BITS'length - 1 downto 0);
242			signal StmBuf_MetaOut_Data								: std_logic_vector(isum(TXSTMBUF_META_BITS) - 1 downto 0);
243	
244			signal StmBuf_Meta_SrcIPv4Address_Data		: std_logic_vector(TX_StmMux_SrcIPv4Address_Data'range);
245			signal StmBuf_Meta_DestIPv4Address_Data		: std_logic_vector(TX_StmMux_DestIPv4Address_Data'range);
246			signal StmBuf_Meta_Length									: std_logic_vector(TX_StmMux_Length'range);
247			signal StmBuf_Meta_Protocol								: std_logic_vector(TX_StmMux_Protocol'range);
248	
249			signal StmMux_MetaIn_Data									: std_logic_vector(isum(TXSTMMUX_META_BITS) - 1 downto 0);
250	
251		begin
252			StmBuf_MetaIn_Data(high(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_SRCADR)	downto low(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_SRCADR))	<= TX_Meta_SrcIPv4Address_Data(i);
253			StmBuf_MetaIn_Data(high(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_DESTADR)	downto low(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_DESTADR))	<= TX_Meta_DestIPv4Address_Data(i);
254			StmBuf_MetaIn_Data(high(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_LENGTH)	downto low(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_LENGTH))	<= TX_Meta_Length(i);
255	
256	--		TX_Meta_rst(i)									<= Meta_rst;
257			TX_Meta_SrcIPv4Address_nxt(i)		<= StmBuf_MetaIn_nxt(TXSTMBUF_META_STREAMID_SRCADR);
258			TX_Meta_DestIPv4Address_nxt(i)	<= StmBuf_MetaIn_nxt(TXSTMBUF_META_STREAMID_DESTADR);
259	
260			TX_StmBuf : entity PoC.stream_Buffer
261				generic map (
262					FRAMES												=> 2,
263					DATA_BITS											=> 8,
264					DATA_FIFO_DEPTH								=> 16,
265					META_BITS											=> TXSTMBUF_META_BITS,
266					META_FIFO_DEPTH								=> TXSTMBUF_META_FIFO_DEPTHS
267				)
268				port map (
269					Clock													=> Clock,
270					Reset													=> Reset,
271	
272					In_Valid											=> TX_Valid(i),
273					In_Data												=> TX_Data(i),
274					In_SOF												=> TX_SOF(i),
275					In_EOF												=> TX_EOF(i),
276					In_Ack												=> TX_Ack	(i),
277					In_Meta_rst										=> TX_Meta_rst(i),
278					In_Meta_nxt										=> StmBuf_MetaIn_nxt,
279					In_Meta_Data									=> StmBuf_MetaIn_Data,
280	
281					Out_Valid											=> StmMux_In_Valid(i),
282					Out_Data											=> StmBuf_DataOut,
283					Out_SOF												=> StmMux_In_SOF(i),
284					Out_EOF												=> StmMux_In_EOF(i),
285					Out_Ack												=> StmMux_In_Ack	(i),
286					Out_Meta_rst									=> StmBuf_Meta_rst,
287					Out_Meta_nxt									=> StmBuf_MetaOut_nxt,
288					Out_Meta_Data									=> StmBuf_MetaOut_Data
289				);
290	
291			-- unpack buffer metadata to signals
292			StmBuf_Meta_SrcIPv4Address_Data											<= StmBuf_MetaOut_Data(high(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_SRCADR)	downto low(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_SRCADR));
293			StmBuf_Meta_DestIPv4Address_Data										<= StmBuf_MetaOut_Data(high(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_DESTADR)	downto low(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_DESTADR));
294			StmBuf_Meta_Length																	<= StmBuf_MetaOut_Data(high(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_LENGTH)	downto low(TXSTMBUF_META_BITS, TXSTMBUF_META_STREAMID_LENGTH));
295	
296			StmBuf_Meta_rst																			<= StmMux_In_Meta_rev(i, TXSTMMUX_META_RST_BIT);
297			StmBuf_MetaOut_nxt(TXSTMBUF_META_STREAMID_SRCADR)		<= StmMux_In_Meta_rev(i, TXSTMMUX_META_SRC_NXT_BIT);
298			StmBuf_MetaOut_nxt(TXSTMBUF_META_STREAMID_DESTADR)	<= StmMux_In_Meta_rev(i, TXSTMMUX_META_DEST_NXT_BIT);
299			StmBuf_MetaOut_nxt(TXSTMBUF_META_STREAMID_LENGTH)		<= '0';
300	
301			-- repack metadata into 1 dim vector for mux
302			StmMux_MetaIn_Data(high(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_SRCADR)		downto low(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_SRCADR))		<= StmBuf_Meta_SrcIPv4Address_Data;
303			StmMux_MetaIn_Data(high(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_DESTADR)		downto low(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_DESTADR))		<= StmBuf_Meta_DestIPv4Address_Data;
304			StmMux_MetaIn_Data(high(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_LENGTH)		downto low(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_LENGTH))		<= StmBuf_Meta_Length;
305			StmMux_MetaIn_Data(high(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_PROTOCOL)	downto low(TXSTMMUX_META_BITS, TXSTMMUX_META_STREAMID_PROTOCOL))	<= PACKET_TYPES(i);
306	
307			-- assign vectors to matrix
308			assign_row(StmMux_In_Data, StmBuf_DataOut, i);
309			assign_row(StmMux_In_Meta, StmMux_MetaIn_Data,	 i);
310		end generate;
311	
312	
313		TX_StmMux : entity PoC.stream_Mux
314			generic map (
315				PORTS									=> IPV4_SWITCH_PORTS,
316				DATA_BITS							=> TX_StmMux_Data'length,
317				META_BITS							=> isum(TXSTMMUX_META_BITS),
318				META_REV_BITS					=> TXSTMMUX_META_REV_BITS
319			)
320			port map (
321				Clock									=> Clock,
322				Reset									=> Reset,
323	
324				In_Valid							=> StmMux_In_Valid,
325				In_Data								=> StmMux_In_Data,
326				In_Meta								=> StmMux_In_Meta,
327				In_Meta_rev						=> StmMux_In_Meta_rev,
328				In_SOF								=> StmMux_In_SOF,
329				In_EOF								=> StmMux_In_EOF,
330				In_Ack								=> StmMux_In_Ack,
331	
332				Out_Valid							=> TX_StmMux_Valid,
333				Out_Data							=> TX_StmMux_Data,
334				Out_Meta							=> TX_StmMux_Meta,
335				Out_Meta_rev					=> TX_StmMux_Meta_rev,
336				Out_SOF								=> TX_StmMux_SOF,
337				Out_EOF								=> TX_StmMux_EOF,
338				Out_Ack								=> IPv4_TX_Ack
339			);
340	
341		TX_StmMux_SrcIPv4Address_Data										<= TX_StmMux_Meta(TX_StmMux_SrcIPv4Address_Data'range);
342		TX_StmMux_DestIPv4Address_Data									<= TX_StmMux_Meta(TX_StmMux_DestIPv4Address_Data'range);
343		TX_StmMux_Length																<= TX_StmMux_Meta(TX_StmMux_Length'range);
344		TX_StmMux_Protocol															<= TX_StmMux_Meta(TX_StmMux_Protocol'range);
345	
346		TX_StmMux_Meta_rev(TXSTMMUX_META_RST_BIT)				<= IPv4_TX_Meta_rst;
347		TX_StmMux_Meta_rev(TXSTMMUX_META_SRC_NXT_BIT)		<= IPv4_TX_Meta_SrcIPv4Address_nxt;
348		TX_StmMux_Meta_rev(TXSTMMUX_META_DEST_NXT_BIT)	<= IPv4_TX_Meta_DestIPv4Address_nxt;
349	
350		IPv4_TX : entity PoC.ipv4_TX
351			generic map (
352				DEBUG													=> DEBUG
353			)
354			port map (
355				Clock													=> Clock,
356				Reset													=> Reset,
357	
358				In_Valid											=> TX_StmMux_Valid,
359				In_Data												=> TX_StmMux_Data,
360				In_SOF												=> TX_StmMux_SOF,
361				In_EOF												=> TX_StmMux_EOF,
362				In_Ack												=> IPv4_TX_Ack,
363				In_Meta_rst										=> IPv4_TX_Meta_rst,
364				In_Meta_SrcIPv4Address_nxt		=> IPv4_TX_Meta_SrcIPv4Address_nxt,
365				In_Meta_SrcIPv4Address_Data		=> TX_StmMux_SrcIPv4Address_Data,
366				In_Meta_DestIPv4Address_nxt		=> IPv4_TX_Meta_DestIPv4Address_nxt,
367				In_Meta_DestIPv4Address_Data	=> TX_StmMux_DestIPv4Address_Data,
368				In_Meta_Length								=> TX_StmMux_Length,
369				In_Meta_Protocol							=> TX_StmMux_Protocol,
370	
371				ARP_IPCache_Query							=> ARP_IPCache_Query,
372				ARP_IPCache_IPv4Address_rst		=> ARP_IPCache_IPv4Address_rst,
373				ARP_IPCache_IPv4Address_nxt		=> ARP_IPCache_IPv4Address_nxt,
374				ARP_IPCache_IPv4Address_Data	=> ARP_IPCache_IPv4Address_Data,
375	
376				ARP_IPCache_Valid							=> ARP_IPCache_Valid,
377				ARP_IPCache_MACAddress_rst		=> ARP_IPCache_MACAddress_rst,
378				ARP_IPCache_MACAddress_nxt		=> ARP_IPCache_MACAddress_nxt,
379				ARP_IPCache_MACAddress_Data		=> ARP_IPCache_MACAddress_Data,
380	
381				Out_Valid											=> MAC_TX_Valid,
382				Out_Data											=> MAC_TX_Data,
383				Out_SOF												=> MAC_TX_SOF,
384				Out_EOF												=> MAC_TX_EOF,
385				Out_Ack												=> MAC_TX_Ack,
386				Out_Meta_rst									=> MAC_TX_Meta_rst,
387				Out_Meta_DestMACAddress_nxt		=> MAC_TX_Meta_DestMACAddress_nxt,
388				Out_Meta_DestMACAddress_Data	=> MAC_TX_Meta_DestMACAddress_Data
389			);
390	
391	-- =============================================================================
392	-- RX Path
393	-- =============================================================================
394		IPv4_RX : entity PoC.ipv4_RX
395			generic map (
396				DEBUG														=> DEBUG
397			)
398			port map (
399				Clock														=> Clock,
400				Reset														=> Reset,
401	
402				In_Valid												=> MAC_RX_Valid,
403				In_Data													=> MAC_RX_Data,
404				In_SOF													=> MAC_RX_SOF,
405				In_EOF													=> MAC_RX_EOF,
406				In_Ack													=> MAC_RX_Ack,
407				In_Meta_rst											=> MAC_RX_Meta_rst,
408				In_Meta_SrcMACAddress_nxt				=> MAC_RX_Meta_SrcMACAddress_nxt,
409				In_Meta_SrcMACAddress_Data			=> MAC_RX_Meta_SrcMACAddress_Data,
410				In_Meta_DestMACAddress_nxt			=> MAC_RX_Meta_DestMACAddress_nxt,
411				In_Meta_DestMACAddress_Data			=> MAC_RX_Meta_DestMACAddress_Data,
412				In_Meta_EthType									=> MAC_RX_Meta_EthType,
413	
414				Out_Valid												=> IPv4_RX_Valid,
415				Out_Data												=> IPv4_RX_Data,
416				Out_SOF													=> IPv4_RX_SOF,
417				Out_EOF													=> IPv4_RX_EOF,
418				Out_Ack													=> RX_StmDeMux_Ack,
419				Out_Meta_rst										=> RX_StmDeMux_Meta_rst,
420				Out_Meta_SrcMACAddress_nxt			=> RX_StmDeMux_Meta_SrcMACAddress_nxt,
421				Out_Meta_SrcMACAddress_Data			=> IPv4_RX_Meta_SrcMACAddress_Data,
422				Out_Meta_DestMACAddress_nxt			=> RX_StmDeMux_Meta_DestMACAddress_nxt,
423				Out_Meta_DestMACAddress_Data		=> IPv4_RX_Meta_DestMACAddress_Data,
424				Out_Meta_EthType								=> IPv4_RX_Meta_EthType,
425				Out_Meta_SrcIPv4Address_nxt			=> RX_StmDeMux_Meta_SrcIPv4Address_nxt,
426				Out_Meta_SrcIPv4Address_Data		=> IPv4_RX_Meta_SrcIPv4Address_Data,
427				Out_Meta_DestIPv4Address_nxt		=> RX_StmDeMux_Meta_DestIPv4Address_nxt,
428				Out_Meta_DestIPv4Address_Data		=> IPv4_RX_Meta_DestIPv4Address_Data,
429				Out_Meta_Length									=> IPv4_RX_Meta_Length,
430				Out_Meta_Protocol								=> IPv4_RX_Meta_Protocol
431			);
432	
433		genStmDeMux_Control : for i in 0 to IPV4_SWITCH_PORTS - 1 generate
434			StmDeMux_Control(i)		<= to_sl(IPv4_RX_Meta_Protocol = PACKET_TYPES(i));
435		end generate;
436	
437		-- decompress meta_rev vector to single bits
438		RX_StmDeMux_Meta_rst									<= RX_StmDeMux_MetaIn_rev(STMDEMUX_META_RST_BIT);
439		RX_StmDeMux_Meta_SrcMACAddress_nxt		<= RX_StmDeMux_MetaIn_rev(STMDEMUX_META_MACSRC_NXT_BIT);
440		RX_StmDeMux_Meta_DestMACAddress_nxt		<= RX_StmDeMux_MetaIn_rev(STMDEMUX_META_MACDEST_NXT_BIT);
441		RX_StmDeMux_Meta_SrcIPv4Address_nxt		<= RX_StmDeMux_MetaIn_rev(STMDEMUX_META_IPV4SRC_NXT_BIT);
442		RX_StmDeMux_Meta_DestIPv4Address_nxt	<= RX_StmDeMux_MetaIn_rev(STMDEMUX_META_IPV4DEST_NXT_BIT);
443	
444		-- compress meta data vectors to single meta data vector
445		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC))		<= IPv4_RX_Meta_SrcMACAddress_Data;
446		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC))	<= IPv4_RX_Meta_DestMACAddress_Data;
447		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE))	<= IPv4_RX_Meta_EthType;
448		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP))		<= IPv4_RX_Meta_SrcIPv4Address_Data;
449		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP))		<= IPv4_RX_Meta_DestIPv4Address_Data;
450		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH))		<= IPv4_RX_Meta_Length;
451		RX_StmDeMux_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO))		<= IPv4_RX_Meta_Protocol;
452	
453		RX_LLDeMux : entity PoC.stream_DeMux
454			generic map (
455				PORTS										=> IPV4_SWITCH_PORTS,
456				DATA_BITS								=> STMDEMUX_DATA_BITS,
457				META_BITS								=> isum(STMDEMUX_META_BITS),
458				META_REV_BITS						=> STMDEMUX_META_REV_BITS
459			)
460			port map (
461				Clock										=> Clock,
462				Reset										=> Reset,
463	
464				DeMuxControl						=> StmDeMux_Control,
465	
466				In_Valid								=> IPv4_RX_Valid,
467				In_Data									=> IPv4_RX_Data,
468				In_Meta									=> RX_StmDeMux_MetaIn,
469				In_Meta_rev							=> RX_StmDeMux_MetaIn_rev,
470				In_SOF									=> IPv4_RX_SOF,
471				In_EOF									=> IPv4_RX_EOF,
472				In_Ack									=> RX_StmDeMux_Ack,
473	
474				Out_Valid								=> RX_Valid,
475				Out_Data								=> RX_StmDeMux_Data,
476				Out_Meta								=> RX_StmDeMux_MetaOut,
477				Out_Meta_rev						=> RX_StmDeMux_MetaOut_rev,
478				Out_SOF									=> RX_SOF,
479				Out_EOF									=> RX_EOF,
480				Out_Ack									=> RX_Ack
481			);
482	
483		assign_col(RX_StmDeMux_MetaOut_rev, RX_Meta_rst,									STMDEMUX_META_RST_BIT);
484		assign_col(RX_StmDeMux_MetaOut_rev, RX_Meta_SrcMACAddress_nxt,		STMDEMUX_META_MACSRC_NXT_BIT);
485		assign_col(RX_StmDeMux_MetaOut_rev, RX_Meta_DestMACAddress_nxt,		STMDEMUX_META_MACDEST_NXT_BIT);
486		assign_col(RX_StmDeMux_MetaOut_rev, RX_Meta_SrcIPv4Address_nxt,		STMDEMUX_META_IPV4SRC_NXT_BIT);
487		assign_col(RX_StmDeMux_MetaOut_rev, RX_Meta_DestIPv4Address_nxt,	STMDEMUX_META_IPV4DEST_NXT_BIT);
488	
489		-- new slm_slice funtion to avoid generate statement for wiring => cut multiple columns over all rows and convert to slvv_*
490		RX_Data													<= to_slvv_8(RX_StmDeMux_Data);
491		RX_Meta_SrcMACAddress_Data			<= to_slvv_8(	slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC)));
492		RX_Meta_DestMACAddress_Data			<= to_slvv_8(	slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC), low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC)));
493		RX_Meta_EthType									<= to_slvv_16(slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE), low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE)));
494		RX_Meta_SrcIPv4Address_Data			<= to_slvv_8(	slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP)));
495		RX_Meta_DestIPv4Address_Data		<= to_slvv_8(	slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP)));
496		RX_Meta_Length									<= to_slvv_16(slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH)));
497		RX_Meta_Protocol								<= to_slvv_8(	slm_slice_cols(RX_StmDeMux_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO)));
498	
499	end architecture;
