242		constant STMDEMUX_DATA_BITS									: natural					:= 8;							--
243		constant STMDEMUX_META_BITS									: T_POSVEC				:= (
244			STMDEMUX_META_STREAMID_SRCMAC			=> 8,
245			STMDEMUX_META_STREAMID_DESTMAC 		=> 8,
