270	
271	begin
272		assert ((IP_VERSION = 4) or (IP_VERSION = 6)) report "Unsupported Internet Protocol (IP) version."	severity ERROR;
273	
274	-- =============================================================================
275	-- TX Path
276	-- =============================================================================
277		StmMux_In_Data		<= to_slm(TX_Data);
278	
279		genStmMuxIn : for i in 0 to UDP_SWITCH_PORTS - 1 generate
280			signal Meta			: std_logic_vector(isum(STMMUX_META_BITS) - 1 downto 0);
281		begin
282			Meta(high(STMMUX_META_BITS, STMMUX_META_STREAMID_SRCIP)			downto	low(STMMUX_META_BITS, STMMUX_META_STREAMID_SRCIP))		<= TX_Meta_SrcIPAddress_Data(i);
283			Meta(high(STMMUX_META_BITS, STMMUX_META_STREAMID_DESTIP)		downto	low(STMMUX_META_BITS, STMMUX_META_STREAMID_DESTIP))		<= TX_Meta_DestIPAddress_Data(i);
284			Meta(high(STMMUX_META_BITS, STMMUX_META_STREAMID_SRCPORT)		downto	low(STMMUX_META_BITS, STMMUX_META_STREAMID_SRCPORT))	<= TX_Meta_SrcPort(i);
285			Meta(high(STMMUX_META_BITS, STMMUX_META_STREAMID_DESTPORT)	downto	low(STMMUX_META_BITS, STMMUX_META_STREAMID_DESTPORT))	<= TX_Meta_DestPort(i);
286			Meta(high(STMMUX_META_BITS, STMMUX_META_STREAMID_LENGTH)		downto	low(STMMUX_META_BITS, STMMUX_META_STREAMID_LENGTH))		<= TX_Meta_Length(i);
287	
288			assign_row(StmMux_In_Meta, Meta,	i);
289		end generate;
290	
291		TX_Meta_rst								<= get_col(StmMux_In_Meta_rev,	STMMUX_META_RST_BIT);
292		TX_Meta_SrcIPAddress_nxt	<= get_col(StmMux_In_Meta_rev,	STMMUX_META_SRCIP_NXT_BIT);
293		TX_Meta_DestIPAddress_nxt	<= get_col(StmMux_In_Meta_rev,	STMMUX_META_DESTIP_NXT_BIT);
294	
295		TX_StmMux : entity PoC.stream_Mux
296			generic map (
297				PORTS									=> UDP_SWITCH_PORTS,
298				DATA_BITS							=> StmMux_Out_Data'length,
299				META_BITS							=> isum(STMMUX_META_BITS),
300				META_REV_BITS					=> STMMUX_META_REV_BITS
301			)
302			port map (
303				Clock									=> Clock,
304				Reset									=> Reset,
305	
306				In_Valid							=> TX_Valid,
307				In_Data								=> StmMux_In_Data,
308				In_Meta								=> StmMux_In_Meta,
309				In_Meta_rev						=> StmMux_In_Meta_rev,
310				In_SOF								=> TX_SOF,
311				In_EOF								=> TX_EOF,
312				In_Ack								=> TX_Ack,
313	
314				Out_Valid							=> StmMux_Out_Valid,
315				Out_Data							=> StmMux_Out_Data,
316				Out_Meta							=> StmMux_Out_Meta,
317				Out_Meta_rev					=> StmMux_Out_Meta_rev,
318				Out_SOF								=> StmMux_Out_SOF,
319				Out_EOF								=> StmMux_Out_EOF,
320				Out_Ack								=> TX_FCS_Ack
321			);
322	
323		StmMux_Out_Meta_rev(STMMUX_META_RST_BIT)				<= TX_FCS_MetaIn_rst;
324		StmMux_Out_Meta_rev(STMMUX_META_SRCIP_NXT_BIT)	<= TX_FCS_MetaIn_nxt(TX_FCS_META_STREAMID_SRCIP);
325		StmMux_Out_Meta_rev(STMMUX_META_DESTIP_NXT_BIT)	<= TX_FCS_MetaIn_nxt(TX_FCS_META_STREAMID_DESTIP);
326	
327		TX_FCS_MetaIn_Data	<= StmMux_Out_Meta;
328	
329		TX_FCS : entity PoC.net_FrameChecksum
330			generic map (
331				MAX_FRAMES						=> 4,
332				MAX_FRAME_LENGTH			=> 2048,
333				META_BITS							=> TX_FCS_META_BITS,
334				META_FIFO_DEPTH				=> TX_FCS_META_FIFO_DEPTHS
335			)
336			port map (
337				Clock									=> Clock,
338				Reset									=> Reset,
339	
340				In_Valid							=> StmMux_Out_Valid,
341				In_Data								=> StmMux_Out_Data,
342				In_SOF								=> StmMux_Out_SOF,
343				In_EOF								=> StmMux_Out_EOF,
344				In_Ack								=> TX_FCS_Ack,
345				In_Meta_rst						=> TX_FCS_MetaIn_rst,
346				In_Meta_nxt						=> TX_FCS_MetaIn_nxt,
347				In_Meta_Data					=> TX_FCS_MetaIn_Data,
348	
349				Out_Valid							=> TX_FCS_Valid,
350				Out_Data							=> TX_FCS_Data,
351				Out_SOF								=> TX_FCS_SOF,
352				Out_EOF								=> TX_FCS_EOF,
353				Out_Ack								=> UDP_TX_Ack,
354				Out_Meta_rst					=> TX_FCS_MetaOut_rst,
355				Out_Meta_nxt					=> TX_FCS_MetaOut_nxt,
356				Out_Meta_Data					=> TX_FCS_MetaOut_Data,
357				Out_Meta_Checksum			=> TX_FCS_Meta_Checksum,
358				Out_Meta_Length				=> TX_FCS_Meta_Length
359			);
360	
361		TX_FCS_MetaOut_rst																<= UDP_TX_Meta_rst;
362		TX_FCS_MetaOut_nxt(TX_FCS_META_STREAMID_SRCIP)		<= UDP_TX_Meta_SrcIPAddress_nxt;
363		TX_FCS_MetaOut_nxt(TX_FCS_META_STREAMID_DESTIP)		<= UDP_TX_Meta_DestIPAddress_nxt;
364		TX_FCS_MetaOut_nxt(TX_FCS_META_STREAMID_SRCPORT)	<= '0';
365		TX_FCS_MetaOut_nxt(TX_FCS_META_STREAMID_DESTPORT)	<= '0';
366	
367		TX_FCS_Meta_SrcIPAddress_Data			<= TX_FCS_MetaOut_Data(high(TX_FCS_META_BITS, TX_FCS_META_STREAMID_SRCIP)		 downto low(TX_FCS_META_BITS, TX_FCS_META_STREAMID_SRCIP));
368		TX_FCS_Meta_DestIPAddress_Data		<= TX_FCS_MetaOut_Data(high(TX_FCS_META_BITS, TX_FCS_META_STREAMID_DESTIP)	 downto low(TX_FCS_META_BITS, TX_FCS_META_STREAMID_DESTIP));
369		TX_FCS_Meta_SrcPort								<= TX_FCS_MetaOut_Data(high(TX_FCS_META_BITS, TX_FCS_META_STREAMID_SRCPORT)	 downto low(TX_FCS_META_BITS, TX_FCS_META_STREAMID_SRCPORT));
370		TX_FCS_Meta_DestPort							<= TX_FCS_MetaOut_Data(high(TX_FCS_META_BITS, TX_FCS_META_STREAMID_DESTPORT) downto low(TX_FCS_META_BITS, TX_FCS_META_STREAMID_DESTPORT));
371	--	TX_FCS_Meta_Length								<= TX_FCS_MetaOut_Data(high(TX_FCS_META_BITS, TX_FCS_META_STREAMID_LEN)			 downto low(TX_FCS_META_BITS, TX_FCS_META_STREAMID_LEN));
372	
373		TX_UDP : entity PoC.udp_TX
374			generic map (
375				DEBUG												=> DEBUG,
376				IP_VERSION									=> IP_VERSION
377			)
378			port map (
379				Clock												=> Clock,
380				Reset												=> Reset,
381	
382				In_Valid										=> TX_FCS_Valid,
383				In_Data											=> TX_FCS_Data,
384				In_SOF											=> TX_FCS_SOF,
385				In_EOF											=> TX_FCS_EOF,
386				In_Ack											=> UDP_TX_Ack,
387				In_Meta_rst									=> UDP_TX_Meta_rst,
388				In_Meta_SrcIPAddress_nxt		=> UDP_TX_Meta_SrcIPAddress_nxt,
389				In_Meta_SrcIPAddress_Data		=> TX_FCS_Meta_SrcIPAddress_Data,
390				In_Meta_DestIPAddress_nxt		=> UDP_TX_Meta_DestIPAddress_nxt,
391				In_Meta_DestIPAddress_Data	=> TX_FCS_Meta_DestIPAddress_Data,
392				In_Meta_SrcPort							=> TX_FCS_Meta_SrcPort,
393				In_Meta_DestPort						=> TX_FCS_Meta_DestPort,
394				In_Meta_Length							=> TX_FCS_Meta_Length,
395				In_Meta_Checksum						=> TX_FCS_Meta_Checksum,
396	
397				Out_Valid										=> IP_TX_Valid,
398				Out_Data										=> IP_TX_Data,
399				Out_SOF											=> IP_TX_SOF,
400				Out_EOF											=> IP_TX_EOF,
401				Out_Ack											=> IP_TX_Ack,
402				Out_Meta_rst								=> IP_TX_Meta_rst,
403				Out_Meta_SrcIPAddress_nxt		=> IP_TX_Meta_SrcIPAddress_nxt,
404				Out_Meta_SrcIPAddress_Data	=> IP_TX_Meta_SrcIPAddress_Data,
405				Out_Meta_DestIPAddress_nxt	=> IP_TX_Meta_DestIPAddress_nxt,
406				Out_Meta_DestIPAddress_Data	=> IP_TX_Meta_DestIPAddress_Data,
407				Out_Meta_Length							=> IP_TX_Meta_Length
408			);
409	
410	-- =============================================================================
411	-- RX Path
412	-- =============================================================================
413		RX_UDP : entity PoC.udp_RX
414			generic map (
415				DEBUG														=> DEBUG,
416				IP_VERSION											=> IP_VERSION
417			)
418			port map (
419				Clock														=> Clock,
420				Reset														=> Reset,
421	
422				In_Valid												=> IP_RX_Valid,
423				In_Data													=> IP_RX_Data,
424				In_SOF													=> IP_RX_SOF,
425				In_EOF													=> IP_RX_EOF,
426				In_Ack													=> IP_RX_Ack,
427				In_Meta_rst											=> IP_RX_Meta_rst,
428				In_Meta_SrcMACAddress_nxt				=> IP_RX_Meta_SrcMACAddress_nxt,
429				In_Meta_SrcMACAddress_Data			=> IP_RX_Meta_SrcMACAddress_Data,
430				In_Meta_DestMACAddress_nxt			=> IP_RX_Meta_DestMACAddress_nxt,
431				In_Meta_DestMACAddress_Data			=> IP_RX_Meta_DestMACAddress_Data,
432				In_Meta_EthType									=> IP_RX_Meta_EthType,
433				In_Meta_SrcIPAddress_nxt				=> IP_RX_Meta_SrcIPAddress_nxt,
434				In_Meta_SrcIPAddress_Data				=> IP_RX_Meta_SrcIPAddress_Data,
435				In_Meta_DestIPAddress_nxt				=> IP_RX_Meta_DestIPAddress_nxt,
436				In_Meta_DestIPAddress_Data			=> IP_RX_Meta_DestIPAddress_Data,
437				In_Meta_Length									=> IP_RX_Meta_Length,
438				In_Meta_Protocol								=> IP_RX_Meta_Protocol,
439	
440				Out_Valid												=> UDP_RX_Valid,
441				Out_Data												=> UDP_RX_Data,
442				Out_SOF													=> UDP_RX_SOF,
443				Out_EOF													=> UDP_RX_EOF,
444				Out_Ack													=> StmDeMux_Out_Ack,
445				Out_Meta_rst										=> StmDeMux_Out_Meta_rst,
446				Out_Meta_SrcMACAddress_nxt			=> StmDeMux_Out_Meta_SrcMACAddress_nxt,
447				Out_Meta_SrcMACAddress_Data			=> UDP_RX_Meta_SrcMACAddress_Data,
448				Out_Meta_DestMACAddress_nxt			=> StmDeMux_Out_Meta_DestMACAddress_nxt,
449				Out_Meta_DestMACAddress_Data		=> UDP_RX_Meta_DestMACAddress_Data,
450				Out_Meta_EthType								=> UDP_RX_Meta_EthType,
451				Out_Meta_SrcIPAddress_nxt				=> StmDeMux_Out_Meta_SrcIPAddress_nxt,
452				Out_Meta_SrcIPAddress_Data			=> UDP_RX_Meta_SrcIPAddress_Data,
453				Out_Meta_DestIPAddress_nxt			=> StmDeMux_Out_Meta_DestIPAddress_nxt,
454				Out_Meta_DestIPAddress_Data			=> UDP_RX_Meta_DestIPAddress_Data,
455				Out_Meta_Length									=> UDP_RX_Meta_Length,
456				Out_Meta_Protocol								=> UDP_RX_Meta_Protocol,
457				Out_Meta_SrcPort								=> UDP_RX_Meta_SrcPort,
458				Out_Meta_DestPort								=> UDP_RX_Meta_DestPort
459			);
460	
461		genStmDeMux_Control : for i in 0 to UDP_SWITCH_PORTS - 1 generate
462			StmDeMux_Control(i)		<= to_sl(UDP_RX_Meta_DestPort = PORTPAIRS(i).Ingress);
463		end generate;
464	
465		-- decompress meta_rev vector to single bits
466		StmDeMux_Out_Meta_rst									<= StmDeMux_Out_MetaIn_rev(STMDEMUX_META_RST_BIT);
467		StmDeMux_Out_Meta_SrcMACAddress_nxt		<= StmDeMux_Out_MetaIn_rev(STMDEMUX_META_MACSRC_NXT_BIT);
468		StmDeMux_Out_Meta_DestMACAddress_nxt	<= StmDeMux_Out_MetaIn_rev(STMDEMUX_META_MACDEST_NXT_BIT);
469		StmDeMux_Out_Meta_SrcIPAddress_nxt		<= StmDeMux_Out_MetaIn_rev(STMDEMUX_META_IPSRC_NXT_BIT);
470		StmDeMux_Out_Meta_DestIPAddress_nxt		<= StmDeMux_Out_MetaIn_rev(STMDEMUX_META_IPDEST_NXT_BIT);
471	
472		-- compress meta data vectors to single meta data vector
473		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC))		<= UDP_RX_Meta_SrcMACAddress_Data;
474		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC))	<= UDP_RX_Meta_DestMACAddress_Data;
475		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE))	<= UDP_RX_Meta_EthType;
476		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP))		<= UDP_RX_Meta_SrcIPAddress_Data;
477		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP))		<= UDP_RX_Meta_DestIPAddress_Data;
478		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH))		<= UDP_RX_Meta_Length;
479		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO)		downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO))		<= UDP_RX_Meta_Protocol;
480		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCPORT) 	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCPORT))	<= UDP_RX_Meta_SrcPort;
481		StmDeMux_Out_MetaIn(high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTPORT)	downto	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTPORT))	<= UDP_RX_Meta_DestPort;
482	
483		RX_StmDeMux : entity PoC.stream_DeMux
484			generic map (
485				PORTS										=> UDP_SWITCH_PORTS,
486				DATA_BITS								=> STMDEMUX_DATA_BITS,
487				META_BITS								=> isum(STMDEMUX_META_BITS),
488				META_REV_BITS						=> STMDEMUX_META_REV_BITS
489			)
490			port map (
491				Clock										=> Clock,
492				Reset										=> Reset,
493	
494				DeMuxControl						=> StmDeMux_Control,
495	
496				In_Valid								=> UDP_RX_Valid,
497				In_Data									=> UDP_RX_Data,
498				In_Meta									=> StmDeMux_Out_MetaIn,
499				In_Meta_rev							=> StmDeMux_Out_MetaIn_rev,
500				In_SOF									=> UDP_RX_SOF,
501				In_EOF									=> UDP_RX_EOF,
502				In_Ack									=> StmDeMux_Out_Ack,
503	
504				Out_Valid								=> RX_Valid,
505				Out_Data								=> StmDeMux_Out_Data,
506				Out_Meta								=> StmDeMux_Out_MetaOut,
507				Out_Meta_rev						=> StmDeMux_Out_MetaOut_rev,
508				Out_SOF									=> RX_SOF,
509				Out_EOF									=> RX_EOF,
510				Out_Ack									=> RX_Ack
511			);
512	
513		assign_col(StmDeMux_Out_MetaOut_rev, RX_Meta_rst,									STMDEMUX_META_RST_BIT);
514		assign_col(StmDeMux_Out_MetaOut_rev, RX_Meta_SrcMACAddress_nxt,		STMDEMUX_META_MACSRC_NXT_BIT);
515		assign_col(StmDeMux_Out_MetaOut_rev, RX_Meta_DestMACAddress_nxt,	STMDEMUX_META_MACDEST_NXT_BIT);
516		assign_col(StmDeMux_Out_MetaOut_rev, RX_Meta_SrcIPAddress_nxt,		STMDEMUX_META_IPSRC_NXT_BIT);
517		assign_col(StmDeMux_Out_MetaOut_rev, RX_Meta_DestIPAddress_nxt,		STMDEMUX_META_IPDEST_NXT_BIT);
518	
519		-- new slm_slice funtion to avoid generate statement for wiring => cut multiple columns over all rows and convert to slvv_*
520		RX_Data													<= to_slvv_8(StmDeMux_Out_Data);
521		RX_Meta_SrcMACAddress_Data			<= to_slvv_8(	slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCMAC)));
522		RX_Meta_DestMACAddress_Data			<= to_slvv_8(	slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTMAC)));
523		RX_Meta_EthType									<= to_slvv_16(slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_ETHTYPE)));
524		RX_Meta_SrcIPAddress_Data				<= to_slvv_8(	slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCIP)));
525		RX_Meta_DestIPAddress_Data			<= to_slvv_8(	slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTIP)));
526		RX_Meta_Length									<= to_slvv_16(slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_LENGTH)));
527		RX_Meta_Protocol								<= to_slvv_8(	slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO),		low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_PROTO)));
528		RX_Meta_SrcPort									<= to_slvv_16(slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCPORT),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_SRCPORT)));
529		RX_Meta_DestPort								<= to_slvv_16(slm_slice_cols(StmDeMux_Out_MetaOut, high(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTPORT),	low(STMDEMUX_META_BITS, STMDEMUX_META_STREAMID_DESTPORT)));
530	
531	end architecture;
532

